import { useMemo, useState } from 'react';
import {
  CartesianGrid,
  ComposedChart,
  Line,
  ReferenceArea,
  ReferenceLine,
  ResponsiveContainer,
  Tooltip,
  XAxis,
  YAxis,
  Legend,
} from 'recharts';
import type { FinancialInputs, ScenarioName } from '../../lib/model';
import {
  ALERT_SPEND_RATE,
  LIQUIDITY_HEALTHY_MONTHS,
  LIQUIDITY_MIN_MONTHS,
  SUSTAINABLE_SPEND_RATE,
  WARN_SPEND_RATE,
  deflateProjection,
  fiscalYears,
  liquidityBand,
  projectAllScenarios,
  projectLiquidity,
  spendRateBand,
} from '../../lib/model';
import { fyLabel, millions, percent } from '../../lib/format';
import { BAND_COLORS, SCENARIO_COLORS } from '../../lib/colors';
import { RecommendedAction } from '../RecommendedAction';

interface Props {
  inputs: FinancialInputs;
  viewMode: 'nominal' | 'real';
  cumInflation: number[];
}

const BAND_BG: Record<'green' | 'yellow' | 'red', string> = {
  green: '#dcfce7',
  yellow: '#fef3c7',
  red: '#fee2e2',
};

export function EndowmentRunway({ inputs, viewMode, cumInflation }: Props) {
  const [floor, setFloor] = useState<number>(40_000_000); // configurable runway floor ($40M default)

  const nominalScenarios = useMemo(() => projectAllScenarios(inputs), [inputs]);
  const scenarios = useMemo(
    () =>
      viewMode === 'real'
        ? nominalScenarios.map((s) => deflateProjection(s, cumInflation))
        : nominalScenarios,
    [nominalScenarios, viewMode, cumInflation]
  );
  const years = fiscalYears();

  // Per-scenario summary stats
  const summary = scenarios.map((s) => {
    const firstYellow = s.years.find((y) => y.spendRate > SUSTAINABLE_SPEND_RATE);
    const firstRed = s.years.find((y) => y.spendRate > WARN_SPEND_RATE);
    const firstAlert = s.years.find((y) => y.spendRate > ALERT_SPEND_RATE);
    const breachFloor = s.years.find((y) => y.endingEndowment < floor);
    const ending = s.years[s.years.length - 1].endingEndowment;
    const startingEndowment = s.years[0].beginningEndowment;
    // Operating-reserve flag: did the projected reserve go negative under policy?
    const reserveBreach = s.years.find((y) => y.operatingReserveEnd < 0);
    const reserveEndFY35 = s.years[s.years.length - 1].operatingReserveEnd;
    const totalGap = s.years.reduce((acc, y) => acc + y.policyDistributionGap, 0);
    return {
      scenario: s.scenario,
      yearsAboveSustainable: s.years.filter((y) => y.spendRate > SUSTAINABLE_SPEND_RATE)
        .length,
      firstYellow: firstYellow?.fiscalYear,
      firstRed: firstRed?.fiscalYear,
      firstAlert: firstAlert?.fiscalYear,
      breachFloor: breachFloor?.fiscalYear,
      endingEndowment: ending,
      delta: ending - startingEndowment,
      reserveBreach: reserveBreach?.fiscalYear,
      reserveEndFY35,
      totalGap,
    };
  });

  const policyOn = inputs.spendingPolicy.enabled;

  // Liquidity coverage: months of operating expenses covered by op reserve
  // (conservative) and op reserve + quasi-endowment (full liquid view, with
  // a board-set liquidation factor — defaults to 1.0 since boards can lift
  // the quasi designation. Set to 0.5 for a stricter "we'd take 6 months
  // to unwind it" view).
  const [liquidationFactor, setLiquidationFactor] = useState<number>(1.0);
  const liquidityByScenario = scenarios.map((s) => ({
    scenario: s.scenario,
    series: projectLiquidity(s, inputs, liquidationFactor),
  }));

  // Compute the runway-tab recommendation: anchor on Pessimistic FY32
  // reserve-only liquidity. <3 mo = urgent; 3-6 mo = watch; ≥6 mo = on-track.
  const pessLiquidity = liquidityByScenario.find((l) => l.scenario === 'Pessimistic')!;
  const pessFY32Liq = pessLiquidity.series[5].reserveOnlyMonths;
  const pessFY35Liq = pessLiquidity.series[8].reserveOnlyMonths;
  const runwayRec =
    pessFY35Liq < 0 || pessFY32Liq < 3
      ? {
          severity: 'urgent' as const,
          headline: `Operating reserve depletes under Pessimistic — ${pessFY32Liq.toFixed(1)} mo by FY32`,
          rationale: (
            <>
              Pessimistic FY32 reserve falls to{' '}
              <strong>{pessFY32Liq.toFixed(1)} months</strong> of expense coverage and{' '}
              <strong>{pessFY35Liq.toFixed(1)} months</strong> by FY35 — under the ASU 2014-15
              substantial-doubt threshold. Quasi-endowment redesignation is the only path back to a
              healthy reserve under this stress.
            </>
          ),
          actions: [
            'Document a board-policy quasi-redesignation trigger (e.g., "if reserve-only months falls below 4, the Finance Committee shall recommend redesignation of $X").',
            'Pre-clear the redesignation language with audit and legal counsel before it is needed.',
            'Brief the Investment Committee on the FY27–FY35 reserve trajectory at the next meeting.',
          ],
        }
      : pessFY32Liq < 6
        ? {
            severity: 'watch' as const,
            headline: `Watch — Pessimistic reserve coverage drops to ${pessFY32Liq.toFixed(1)} mo at FY32`,
            rationale: (
              <>
                Reserve months fall into the NRO best-practice minimum band ({pessFY32Liq.toFixed(1)}{' '}
                mo) under Pessimistic. Total liquid (incl. quasi at factor {liquidationFactor}) is
                comfortable, but the conservative reserve-only view is borderline.
              </>
            ),
            actions: [
              'Confirm the operating-reserve policy minimum at the next Finance Committee.',
              'Track reserve-month trajectory quarterly; review if actuals trend toward Pessimistic.',
            ],
          }
        : {
            severity: 'on-track' as const,
            headline: `Reserve coverage stays healthy — ${pessFY32Liq.toFixed(1)} mo at FY32 even in Pessimistic`,
            rationale: (
              <>
                Reserve-only liquidity holds at{' '}
                <strong>{pessFY32Liq.toFixed(1)} months</strong> of expense coverage at FY32 under
                Pessimistic — comfortably above the NRO 3–6mo best-practice band.
              </>
            ),
            actions: [
              'Annual confirmation at the Finance Committee.',
              'Continue quarterly liquidity tracking against the Pessimistic trajectory.',
            ],
          };

  // Data for the floor chart: ending endowment vs floor.
  // Note: we render the danger zone via <ReferenceArea y1={0} y2={floor}> below,
  // so the chart row no longer needs a "Floor" series — that was the source of the
  // original "red strip painted ON the floor line, not below it" bug flagged in
  // the UX audit.
  const chartData = years.map((fy, i) => {
    const row: Record<string, number | string> = { fyLabel: fyLabel(fy) };
    scenarios.forEach((s) => {
      row[s.scenario] = s.years[i].endingEndowment;
    });
    return row;
  });

  return (
    <div className="space-y-6">
      <RecommendedAction
        context="Liquidity / runway · recommended action"
        severity={runwayRec.severity}
        headline={runwayRec.headline}
        rationale={runwayRec.rationale}
        actions={runwayRec.actions}
      />

      <section className="card">
        <div className="card-header flex items-center justify-between flex-wrap gap-3">
          <div>
            <div className="eyebrow">Endowment runway</div>
            <h2 className="font-head text-base">Ending endowment vs. sustainability floor</h2>
          </div>
          <div className="flex items-center gap-2 text-sm">
            <label className="text-navy/70 font-semibold">Runway floor ($M):</label>
            <input
              type="number"
              step="1"
              className="input-num"
              value={(floor / 1_000_000).toFixed(0)}
              onChange={(e) => setFloor(Number(e.target.value) * 1_000_000)}
            />
          </div>
        </div>
        <div className="card-body">
          <div className="h-[320px]">
            <ResponsiveContainer width="100%" height="100%">
              <ComposedChart data={chartData} margin={{ top: 10, right: 24, bottom: 8, left: 0 }}>
                <CartesianGrid strokeDasharray="2 4" stroke="#101A4C15" />
                <XAxis
                  dataKey="fyLabel"
                  tick={{ fill: '#101A4C', fontSize: 12 }}
                  stroke="#101A4C40"
                />
                <YAxis
                  tick={{ fill: '#101A4C', fontSize: 12 }}
                  tickFormatter={(v) => `$${(v / 1_000_000).toFixed(0)}M`}
                  stroke="#101A4C40"
                  width={64}
                />
                <Tooltip
                  contentStyle={{
                    background: 'white',
                    border: '1px solid #101A4C20',
                    borderRadius: 8,
                    fontFamily: 'Noto Serif, serif',
                  }}
                  formatter={(v: number) => millions(v)}
                />
                <Legend />
                {/* True danger zone: shade everything from $0 up to the floor.
                    Replaces the previous Area-on-line bug (UX audit Tier 1 #2). */}
                <ReferenceArea
                  y1={0}
                  y2={floor}
                  fill="#fee2e2"
                  fillOpacity={0.55}
                  stroke="none"
                  ifOverflow="extendDomain"
                />
                {(['Base', 'Optimistic', 'Pessimistic'] as ScenarioName[]).map((s) => (
                  <Line
                    key={s}
                    type="monotone"
                    dataKey={s}
                    stroke={SCENARIO_COLORS[s]}
                    strokeWidth={2.5}
                    strokeDasharray={s === 'Pessimistic' ? '6 4' : undefined}
                    dot={{ r: 3 }}
                    isAnimationActive={false}
                  />
                ))}
                <ReferenceLine
                  y={floor}
                  stroke="#b91c1c"
                  strokeDasharray="2 4"
                  label={{ value: `Floor ${(floor / 1_000_000).toFixed(0)}M`, position: 'right', fill: '#b91c1c', fontSize: 11 }}
                />
              </ComposedChart>
            </ResponsiveContainer>
          </div>
          <p className="text-xs text-navy/60 mt-3 font-sub">
            The shaded band marks the configurable runway floor. A scenario that crosses below it has
            depleted past the threshold the organization considers operationally sustainable.
          </p>
        </div>
      </section>

      {/* Spend rate heatmap */}
      <section className="card">
        <div className="card-header">
          <div className="eyebrow">Spend-rate guardrails</div>
          <h2 className="font-head text-base">Total expenses ÷ beginning endowment, by year</h2>
        </div>
        <div className="card-body overflow-x-auto">
          <table className="w-full text-sm num">
            <thead>
              <tr className="text-navy/60 uppercase text-xs tracking-wider">
                <th className="text-left py-2 pr-4 font-semibold">Scenario</th>
                {years.map((fy) => (
                  <th key={fy} className="text-center px-2 py-2 font-semibold">
                    {fyLabel(fy)}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {scenarios.map((s) => (
                <tr key={s.scenario} className="border-b border-navy/5">
                  <td className="text-left py-2 pr-4 font-semibold text-navy">
                    {s.scenario}
                  </td>
                  {s.years.map((y) => {
                    const band = spendRateBand(y.spendRate);
                    return (
                      <td
                        key={y.fiscalYear}
                        className="text-center px-2 py-2 font-semibold"
                        style={{
                          background: BAND_BG[band],
                          color: BAND_COLORS[band],
                        }}
                        title={`Spend rate ${percent(y.spendRate, 2)} · expenses ${millions(
                          y.totalExpenses
                        )} · beginning endowment ${millions(y.beginningEndowment)}`}
                      >
                        {percent(y.spendRate, 1)}
                      </td>
                    );
                  })}
                </tr>
              ))}
            </tbody>
          </table>
          <div className="flex items-center gap-4 text-xs mt-3 font-sub">
            <span className="flex items-center gap-2">
              <span
                className="inline-block w-3 h-3 rounded-sm"
                style={{ background: BAND_BG.green, border: `1px solid ${BAND_COLORS.green}` }}
              />
              Sustainable (≤ {percent(SUSTAINABLE_SPEND_RATE, 1)})
            </span>
            <span className="flex items-center gap-2">
              <span
                className="inline-block w-3 h-3 rounded-sm"
                style={{ background: BAND_BG.yellow, border: `1px solid ${BAND_COLORS.yellow}` }}
              />
              Warn (≤ {percent(WARN_SPEND_RATE, 1)})
            </span>
            <span className="flex items-center gap-2">
              <span
                className="inline-block w-3 h-3 rounded-sm"
                style={{ background: BAND_BG.red, border: `1px solid ${BAND_COLORS.red}` }}
              />
              Alert (&gt; {percent(WARN_SPEND_RATE, 1)})
            </span>
          </div>
        </div>
      </section>

      {/* Per-scenario summary cards */}
      <section className="grid grid-cols-1 md:grid-cols-3 gap-4">
        {summary.map((s) => {
          const breached = !!s.breachFloor;
          const allSustainable = s.yearsAboveSustainable === 0;
          return (
            <div key={s.scenario} className="card">
              <div className="card-header flex items-center justify-between">
                <div>
                  <div className="eyebrow">{s.scenario} scenario</div>
                  <h3 className="font-head text-base">FY35 outlook</h3>
                </div>
                <span
                  className={`pill gap-1 ${
                    breached
                      ? 'pill-red'
                      : !allSustainable
                        ? 'pill-yellow'
                        : 'pill-green'
                  }`}
                  aria-label={
                    breached
                      ? 'Floor breached — alert'
                      : !allSustainable
                        ? 'Above sustainable spend — watch'
                        : 'Healthy'
                  }
                >
                  <span aria-hidden="true">{breached ? '✕' : !allSustainable ? '▲' : '●'}</span>
                  {breached ? 'Floor breached' : !allSustainable ? 'Watch' : 'Healthy'}
                </span>
              </div>
              <div className="card-body space-y-2 text-sm">
                <Stat label="FY35 ending endowment" value={millions(s.endingEndowment)} />
                <Stat
                  label="Net change FY27 → FY35"
                  value={`${s.delta >= 0 ? '+' : ''}${millions(s.delta)}`}
                  positive={s.delta >= 0}
                />
                <Stat
                  label="First year above 4.5% spend"
                  value={s.firstYellow ? fyLabel(s.firstYellow) : '—'}
                />
                <Stat
                  label="First year above 6% spend"
                  value={s.firstRed ? fyLabel(s.firstRed) : '—'}
                />
                <Stat
                  label="First year breaching floor"
                  value={s.breachFloor ? fyLabel(s.breachFloor) : '—'}
                  positive={!s.breachFloor}
                />
                {policyOn && (
                  <>
                    <Stat
                      label="Op reserve FY35"
                      value={millions(s.reserveEndFY35)}
                      positive={s.reserveEndFY35 >= 0}
                    />
                    <Stat
                      label="First yr reserve <0"
                      value={s.reserveBreach ? fyLabel(s.reserveBreach) : '—'}
                      positive={!s.reserveBreach}
                    />
                    <Stat
                      label="Cum policy gap (9 yrs)"
                      value={millions(s.totalGap)}
                      positive={s.totalGap <= 0}
                    />
                  </>
                )}
              </div>
            </div>
          );
        })}
      </section>

      {/* Liquidity coverage — months of expenses available. ASU 2014-15
          going-concern signal. Always shown (independent of policy toggle). */}
      <section className="card">
        <div className="card-header flex items-center justify-between flex-wrap gap-3">
          <div>
            <div className="eyebrow">Liquidity coverage</div>
            <h2 className="font-head text-base">
              Months of operating expenses available · ASU 2014-15 going-concern lens
            </h2>
          </div>
          <div className="flex items-center gap-2 text-sm">
            <label className="text-navy/70 font-semibold">Quasi liquidation factor:</label>
            <input
              type="number"
              step="0.1"
              min="0"
              max="1"
              className="input-num w-20"
              value={liquidationFactor}
              onChange={(e) =>
                setLiquidationFactor(Math.max(0, Math.min(1, Number(e.target.value))))
              }
              title="Fraction of quasi-endowment treated as liquid. 1.0 = board can fully redesignate; 0.5 = half could be unwound in ~6 months; 0 = reserve-only view."
            />
          </div>
        </div>
        <div className="card-body overflow-x-auto">
          <table className="w-full text-sm num">
            <thead>
              <tr className="text-navy/60 uppercase text-xs tracking-wider">
                <th className="text-left py-2 pr-4 font-semibold">Scenario</th>
                <th className="text-right px-3 py-2 font-semibold" colSpan={2}>
                  FY27
                </th>
                <th className="text-right px-3 py-2 font-semibold" colSpan={2}>
                  FY32
                </th>
                <th className="text-right px-3 py-2 font-semibold" colSpan={2}>
                  FY35
                </th>
              </tr>
              <tr className="text-navy/50 text-[10px] uppercase tracking-wider border-b border-navy/10">
                <th></th>
                <th className="text-right px-2 py-1 font-semibold">Reserve</th>
                <th className="text-right px-2 py-1 font-semibold">+Quasi</th>
                <th className="text-right px-2 py-1 font-semibold">Reserve</th>
                <th className="text-right px-2 py-1 font-semibold">+Quasi</th>
                <th className="text-right px-2 py-1 font-semibold">Reserve</th>
                <th className="text-right px-2 py-1 font-semibold">+Quasi</th>
              </tr>
            </thead>
            <tbody>
              {liquidityByScenario.map(({ scenario: s, series }) => {
                const fy27 = series[0];
                const fy32 = series[5];
                const fy35 = series[8];
                const cell = (months: number) => {
                  const band = liquidityBand(months);
                  const cls =
                    band === 'red'
                      ? 'text-rose-700 font-semibold'
                      : band === 'amber'
                        ? 'text-amber-700 font-semibold'
                        : 'text-emerald-700';
                  return <span className={cls}>{months.toFixed(1)} mo</span>;
                };
                return (
                  <tr key={s} className="border-b border-navy/5">
                    <td
                      className="text-left py-2 pr-4 font-semibold"
                      style={{ color: '#101A4C' }}
                    >
                      {s}
                    </td>
                    <td className="text-right px-2 py-2">{cell(fy27.reserveOnlyMonths)}</td>
                    <td className="text-right px-2 py-2">{cell(fy27.totalLiquidMonths)}</td>
                    <td className="text-right px-2 py-2">{cell(fy32.reserveOnlyMonths)}</td>
                    <td className="text-right px-2 py-2">{cell(fy32.totalLiquidMonths)}</td>
                    <td className="text-right px-2 py-2">{cell(fy35.reserveOnlyMonths)}</td>
                    <td className="text-right px-2 py-2">{cell(fy35.totalLiquidMonths)}</td>
                  </tr>
                );
              })}
            </tbody>
          </table>
          <div className="flex items-center gap-4 text-xs mt-3 font-sub flex-wrap">
            <span className="flex items-center gap-2 text-rose-700 font-semibold">
              <span aria-hidden="true">✕</span>
              &lt; {LIQUIDITY_MIN_MONTHS} mo (ASU 2014-15 substantial-doubt)
            </span>
            <span className="flex items-center gap-2 text-amber-700 font-semibold">
              <span aria-hidden="true">▲</span>
              {LIQUIDITY_MIN_MONTHS}–{LIQUIDITY_HEALTHY_MONTHS} mo (NRO best-practice min)
            </span>
            <span className="flex items-center gap-2 text-emerald-700 font-semibold">
              <span aria-hidden="true">●</span>
              ≥ {LIQUIDITY_HEALTHY_MONTHS} mo (healthy)
            </span>
          </div>
        </div>
        <div className="card-body border-t border-navy/10 text-xs text-navy/70 font-sub">
          <p>
            <strong className="text-navy">Reserve only</strong> = operating reserve / monthly expense; the conservative "we cannot touch the endowment" view. <strong className="text-navy">+Quasi</strong> = (operating reserve + quasi-endowment × liquidation factor) / monthly expense; assumes the board can redesignate quasi-endowment to operating. Liquidation factor is a governance dial — 1.0 = board can fully redesignate, 0.5 = "half would take 6 months to unwind," 0 = strict reserve-only.
          </p>
          <p className="mt-1">
            {policyOn ? (
              <>
                <strong className="text-navy">Note:</strong> reserve flow is computed under the active spending policy. Below-3-mo reserve-only readings flag that the board should consider a policy distribution increase, a fundraising surge, or a quasi redesignation.
              </>
            ) : (
              <>
                <strong className="text-navy">Note:</strong> spending policy is OFF, so the reserve flow shown is the implicit "what would happen IF the policy were active" series. Toggle on the Policy sub-tab to make this view operational.
              </>
            )}
          </p>
        </div>
      </section>

      {policyOn && (
        <section className="card">
          <div className="card-header">
            <div className="eyebrow">Spending policy view</div>
            <h2 className="font-head text-base">
              Policy distribution vs. actual draw — Base scenario
            </h2>
          </div>
          <div className="card-body overflow-x-auto">
            <table className="w-full text-sm num">
              <thead>
                <tr className="text-navy/60 uppercase text-xs tracking-wider">
                  <th className="text-left py-2 pr-4 font-semibold">FY</th>
                  <th className="text-right px-3 py-2 font-semibold">Policy dist</th>
                  <th className="text-right px-3 py-2 font-semibold">Actual draw</th>
                  <th className="text-right px-3 py-2 font-semibold">Gap (deficit&gt;0)</th>
                  <th className="text-right px-3 py-2 font-semibold">Op reserve end</th>
                </tr>
              </thead>
              <tbody>
                {scenarios[0].years.map((y) => {
                  const actualDraw = Math.max(0, y.totalExpenses - y.fundraising);
                  const reserveBand =
                    y.operatingReserveEnd < 0 ? 'text-rose-700' : 'text-navy';
                  const gapBand =
                    y.policyDistributionGap > 0 ? 'text-rose-700' : 'text-emerald-700';
                  return (
                    <tr key={y.fiscalYear} className="border-b border-navy/5">
                      <td className="text-left py-2 pr-4 font-semibold text-navy">
                        {fyLabel(y.fiscalYear)}
                      </td>
                      <td className="text-right px-3 py-2">{millions(y.policyDistribution)}</td>
                      <td className="text-right px-3 py-2">{millions(actualDraw)}</td>
                      <td className={`text-right px-3 py-2 font-semibold ${gapBand}`}>
                        {millions(y.policyDistributionGap)}
                      </td>
                      <td className={`text-right px-3 py-2 font-semibold ${reserveBand}`}>
                        {millions(y.operatingReserveEnd)}
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
          <div className="card-body border-t border-navy/10 text-xs text-navy/70 font-sub">
            <p>
              <strong className="text-navy">Policy distribution</strong> = {(inputs.spendingPolicy.rate * 100).toFixed(2)}% × trailing {inputs.spendingPolicy.smoothingYears}-year average of {inputs.spendingPolicy.appliesTo === 'restrictedAndQuasi' ? 'restricted + quasi-endowment' : 'restricted only'} pool. Smoothed per UPMIFA prudence convention.
            </p>
            <p className="mt-1">
              <strong className="text-navy">Gap &gt; 0</strong> means actual draw exceeds policy income — the difference flows from operating reserve (bottom column). Persistent gap → reserve depletion → board action required.
            </p>
          </div>
        </section>
      )}
    </div>
  );
}

function Stat({
  label,
  value,
  positive,
}: {
  label: string;
  value: string;
  positive?: boolean;
}) {
  return (
    <div className="flex items-baseline justify-between gap-3 border-b border-navy/5 pb-1">
      <span className="text-navy/60 text-xs uppercase tracking-wide">{label}</span>
      <span
        className={`font-semibold num ${
          positive === false ? 'text-rose-700' : positive === true ? 'text-emerald-700' : 'text-navy'
        }`}
      >
        {value}
      </span>
    </div>
  );
}
