import { useMemo, useState } from 'react';
import type { ReactNode } from 'react';
import {
  CartesianGrid,
  Legend,
  Line,
  LineChart,
  ResponsiveContainer,
  Tooltip,
  XAxis,
  YAxis,
} from 'recharts';
import type { FinancialInputs, ScenarioName } from '../../lib/model';
import {
  HISTORICAL_ENDOWMENT,
  PROGRAM_RATIO_FLOOR,
  SUSTAINABLE_SPEND_RATE,
  deflateProjection,
  projectAllScenarios,
  summarizeScholarBridge,
} from '../../lib/model';
import { runMonteCarlo } from '../../lib/montecarlo';
import { dollars, fyLabel, millions, percent } from '../../lib/format';
import { SCENARIO_COLORS } from '../../lib/colors';
import { RecommendedAction } from '../RecommendedAction';
import type { ActionSeverity } from '../RecommendedAction';

interface Props {
  inputs: FinancialInputs;
  /** 'nominal' | 'real' — when 'real', dollar values are deflated to FY27 $. */
  viewMode: 'nominal' | 'real';
  /** Per-year cumulative inflation factors for the projection window. */
  cumInflation: number[];
}

export function ScenarioOverview({ inputs, viewMode, cumInflation }: Props) {
  const [scenario, setScenario] = useState<ScenarioName>('Base');

  // Project nominally, then optionally deflate for display. Mission-bridge
  // metrics (scholar counts) are unitless so they pass through either way.
  const nominalScenarios = useMemo(() => projectAllScenarios(inputs), [inputs]);
  const scenarios = useMemo(
    () =>
      viewMode === 'real'
        ? nominalScenarios.map((s) => deflateProjection(s, cumInflation))
        : nominalScenarios,
    [nominalScenarios, viewMode, cumInflation]
  );
  const active = scenarios.find((s) => s.scenario === scenario)!;

  // Build chart data: historical + 3 scenarios
  const chartData = useMemo(() => {
    const map = new Map<number, Record<string, number | null>>();
    HISTORICAL_ENDOWMENT.forEach(({ fiscalYear, endingEndowment }) => {
      map.set(fiscalYear, { Historical: endingEndowment });
    });
    scenarios.forEach((s) => {
      s.years.forEach((y) => {
        const row = map.get(y.fiscalYear) ?? {};
        row[s.scenario] = y.endingEndowment;
        map.set(y.fiscalYear, row);
      });
    });
    // Bridge: include FY26 historical endpoint as the start of all scenario lines
    const lastHist = HISTORICAL_ENDOWMENT[HISTORICAL_ENDOWMENT.length - 1];
    const bridge = map.get(lastHist.fiscalYear) ?? {};
    bridge.Base = lastHist.endingEndowment;
    bridge.Optimistic = lastHist.endingEndowment;
    bridge.Pessimistic = lastHist.endingEndowment;
    map.set(lastHist.fiscalYear, bridge);

    return Array.from(map.entries())
      .sort(([a], [b]) => a - b)
      .map(([fiscalYear, vals]) => ({ fiscalYear, ...vals }));
  }, [scenarios]);

  // Row definitions: most rows render with dollars(), but the scholars row
  // formats integer counts and uses a different visual treatment so it doesn't
  // get read as a dollar value.
  type RowDef = {
    key: string;
    label: string;
    emphasis: boolean;
    /** Optional formatter override; default is dollars(value). */
    format?: (value: number) => string;
  };
  const rowDefs: RowDef[] = [
    { key: 'fundraising', label: 'Fundraising', emphasis: false },
    { key: 'marketReturn', label: 'Market return', emphasis: false },
    { key: 'totalIncome', label: 'Total income', emphasis: true },
    { key: 'awardCosts', label: 'Award costs', emphasis: false },
    {
      key: 'scholarsServed',
      label: 'Scholars served',
      emphasis: false,
      format: (v) => (Number.isFinite(v) ? Math.round(v).toLocaleString() : '—'),
    },
    { key: 'opExpenses', label: 'Operating expenses', emphasis: false },
    {
      key: 'opProgram',
      label: '  Program (Form 990 Part IX)',
      emphasis: false,
    },
    {
      key: 'opMgmtGeneral',
      label: '  Mgmt & general',
      emphasis: false,
    },
    {
      key: 'opFundraising',
      label: '  Fundraising',
      emphasis: false,
    },
    { key: 'totalExpenses', label: 'Total expenses', emphasis: true },
    { key: 'totalPL', label: 'Total P&L', emphasis: false },
    { key: 'beginningEndowment', label: 'FY beginning endowment', emphasis: false },
    { key: 'endingEndowment', label: 'FY ending endowment', emphasis: true },
  ];

  // Scholar bridge summaries — one per scenario, for the top-line mission card.
  const bridgeSummaries = scenarios.map((s) => ({
    scenario: s.scenario,
    summary: summarizeScholarBridge(s),
  }));
  const goalFY32 = inputs.scholarGoal[5] ?? 0;

  // Board-summary card: side-by-side Base/Optimistic/Pessimistic comparison +
  // a Monte Carlo stochastic column (p10/p50/p90 of FY35 endowment + insolvency
  // probability). Single-glance scenario read for board members.
  // Use the FLOOR baseline ($40M default) to compute below-floor flags. The
  // runway floor is a tab-level setting; here we use a reasonable default.
  const boardFloor = 40_000_000;
  const summaryRows = scenarios.map((s) => {
    const sum = bridgeSummaries.find((b) => b.scenario === s.scenario)!;
    const minEnd = Math.min(...s.years.map((y) => y.endingEndowment));
    const fy35End = s.years[s.years.length - 1].endingEndowment;
    const avgSpend = s.years.reduce((acc, y) => acc + y.spendRate, 0) / s.years.length;
    const firstBelow = s.years.find((y) => y.endingEndowment < boardFloor);
    return {
      scenario: s.scenario,
      fy35End,
      minEnd,
      fy32Scholars: sum.summary.fy32Served,
      cumScholars: sum.summary.cumulativeServed,
      avgSpend,
      firstBelowFloor: firstBelow?.fiscalYear,
    };
  });

  // Stochastic column: a single MC run over the (possibly auto-linked) inputs.
  // Use the same stochastic defaults as the Stress Test tab so numbers align.
  const mc = useMemo(
    () =>
      runMonteCarlo(inputs, {
        meanReturn: 6.5,
        stdReturn: 12,
        trials: 1000,
        floor: boardFloor,
        df: 6,
      }),
    [inputs]
  );
  const mcEnd = mc.bands[mc.bands.length - 1];
  const probAlways = mc.probAlwaysAboveFloor;
  const probInsolv = mc.probInsolvent;

  // Compute the recommendation severity + content based on the actual scenario
  // state. Logic: anchor on Pessimistic (the conservative read) — its FY35
  // ending and minimum endowment vs. the floor define the action level.
  const pessRow = summaryRows.find((r) => r.scenario === 'Pessimistic')!;
  const recommendation = computeRecommendation({
    pessFY35: pessRow.fy35End,
    pessMin: pessRow.minEnd,
    boardFloor,
    probAlways,
    probInsolv,
    pessFirstBelow: pessRow.firstBelowFloor,
  });

  return (
    <div className="space-y-6">
      {/* Board summary card — at-a-glance scenario comparison. First section
          board members see; designed to print clean on a single sheet. */}
      <section className="card border-2 border-navy/20">
        <div className="card-header flex items-center justify-between flex-wrap gap-3 bg-navy text-white rounded-t-lg">
          <div>
            <div className="eyebrow !text-purple-100">Board summary</div>
            <h2 className="font-head text-lg uppercase tracking-wide-15">
              FY27 – FY35 scenario comparison · all key metrics
            </h2>
          </div>
          <div className="text-xs text-white/70 font-sub">
            Floor reference: {millions(boardFloor)} · {viewMode === 'real' ? 'Real (FY27 $)' : 'Nominal $'}
          </div>
        </div>
        <div className="card-body overflow-x-auto">
          <table className="w-full text-sm num">
            <thead>
              <tr className="text-navy/60 uppercase text-xs tracking-wider border-b-2 border-navy/20">
                <th className="text-left py-2 pr-4 font-semibold">Metric</th>
                {summaryRows.map((r) => (
                  <th
                    key={r.scenario}
                    className="text-right px-3 py-2 font-semibold"
                    style={{ color: SCENARIO_COLORS[r.scenario] }}
                  >
                    {r.scenario}
                  </th>
                ))}
                <th className="text-right px-3 py-2 font-semibold border-l-2 border-navy/20" colSpan={3}>
                  Stochastic (Monte Carlo)
                </th>
              </tr>
              <tr className="text-navy/50 text-[10px] uppercase tracking-wider border-b border-navy/10">
                <th></th>
                <th colSpan={3}></th>
                <th className="text-right px-2 py-1 font-semibold border-l-2 border-navy/20">p10</th>
                <th className="text-right px-2 py-1 font-semibold">p50</th>
                <th className="text-right px-2 py-1 font-semibold">p90</th>
              </tr>
            </thead>
            <tbody>
              <SummaryRow label="FY35 ending endowment">
                {summaryRows.map((r) => (
                  <td key={r.scenario} className="text-right px-3 py-2 font-semibold">
                    {millions(r.fy35End)}
                  </td>
                ))}
                <td className="text-right px-2 py-2 border-l-2 border-navy/20">
                  {millions(mcEnd.p10)}
                </td>
                <td className="text-right px-2 py-2 font-semibold">{millions(mcEnd.p50)}</td>
                <td className="text-right px-2 py-2">{millions(mcEnd.p90)}</td>
              </SummaryRow>

              <SummaryRow label="Min endowment FY27–FY35">
                {summaryRows.map((r) => (
                  <td
                    key={r.scenario}
                    className={`text-right px-3 py-2 font-semibold ${
                      r.minEnd < boardFloor ? 'text-rose-700' : ''
                    }`}
                  >
                    {millions(r.minEnd)}
                  </td>
                ))}
                <td colSpan={3} className="text-right px-2 py-2 text-navy/50 italic border-l-2 border-navy/20">
                  see P(stayed ≥ floor) below
                </td>
              </SummaryRow>

              <SummaryRow label="FY32 scholars served">
                {summaryRows.map((r) => (
                  <td key={r.scenario} className="text-right px-3 py-2">
                    {r.fy32Scholars.toLocaleString()}
                    <span className="text-[10px] text-navy/60 ml-1">
                      ({percent(r.fy32Scholars / Math.max(1, goalFY32), 0)})
                    </span>
                  </td>
                ))}
                <td colSpan={3} className="text-right px-2 py-2 text-navy/50 italic border-l-2 border-navy/20">
                  award costs deterministic
                </td>
              </SummaryRow>

              <SummaryRow label="Cumulative scholars FY27–FY35">
                {summaryRows.map((r) => (
                  <td key={r.scenario} className="text-right px-3 py-2">
                    {r.cumScholars.toLocaleString()}
                  </td>
                ))}
                <td colSpan={3} className="text-right px-2 py-2 text-navy/50 italic border-l-2 border-navy/20">
                  —
                </td>
              </SummaryRow>

              <SummaryRow label="Avg spend rate (net draw / beg endowment)">
                {summaryRows.map((r) => {
                  const band =
                    r.avgSpend > 0.06
                      ? 'text-rose-700'
                      : r.avgSpend > SUSTAINABLE_SPEND_RATE
                        ? 'text-amber-700'
                        : 'text-emerald-700';
                  return (
                    <td key={r.scenario} className={`text-right px-3 py-2 font-semibold ${band}`}>
                      {percent(r.avgSpend, 2)}
                    </td>
                  );
                })}
                <td colSpan={3} className="text-right px-2 py-2 text-navy/50 italic border-l-2 border-navy/20">
                  expense path deterministic
                </td>
              </SummaryRow>

              <SummaryRow label="P(stayed ≥ floor every yr)">
                {summaryRows.map((r) => (
                  <td
                    key={r.scenario}
                    className={`text-right px-3 py-2 font-semibold ${
                      r.firstBelowFloor ? 'text-rose-700' : 'text-emerald-700'
                    }`}
                  >
                    {r.firstBelowFloor ? `breach FY${String(r.firstBelowFloor).slice(-2)}` : 'never'}
                  </td>
                ))}
                <td colSpan={3} className="text-right px-2 py-2 border-l-2 border-navy/20">
                  <span
                    className={`font-semibold ${
                      probAlways >= 0.85 ? 'text-emerald-700' : probAlways >= 0.6 ? 'text-amber-700' : 'text-rose-700'
                    }`}
                  >
                    {percent(probAlways, 0)}
                  </span>
                </td>
              </SummaryRow>

              <SummaryRow label="P(insolvency at any year)">
                {summaryRows.map((r) => {
                  const ins = r.minEnd < 0;
                  return (
                    <td
                      key={r.scenario}
                      className={`text-right px-3 py-2 font-semibold ${
                        ins ? 'text-rose-700' : 'text-emerald-700'
                      }`}
                    >
                      {ins ? 'yes' : 'no'}
                    </td>
                  );
                })}
                <td colSpan={3} className="text-right px-2 py-2 border-l-2 border-navy/20">
                  <span
                    className={`font-semibold ${
                      probInsolv === 0 ? 'text-emerald-700' : probInsolv < 0.05 ? 'text-amber-700' : 'text-rose-700'
                    }`}
                  >
                    {percent(probInsolv, 1)}
                  </span>
                </td>
              </SummaryRow>
            </tbody>
          </table>
        </div>
        <div className="card-body border-t border-navy/10 text-xs text-navy/70 font-sub">
          <p>
            <strong className="text-navy">How to read:</strong> three deterministic scenarios and a 1,000-trial Monte Carlo (Student-t df=6, σ=12%, μ=6.5%) projecting the same nominal inputs. Color: <span className="text-emerald-700 font-semibold">green</span> = at/above sustainable; <span className="text-amber-700 font-semibold">amber</span> = watch; <span className="text-rose-700 font-semibold">red</span> = breach. Avg spend rate band: ≤4.5% green, ≤6% amber, &gt;6% red. Floor probability bands: ≥85% green, ≥60% amber, &lt;60% red.
          </p>
        </div>
      </section>

      <RecommendedAction
        context="Board summary · recommended action"
        severity={recommendation.severity}
        headline={recommendation.headline}
        rationale={recommendation.rationale}
        actions={recommendation.actions}
      />

      <section className="card">
        <div className="card-header flex items-center justify-between">
          <div>
            <div className="eyebrow">Endowment trajectory</div>
            <h2 className="font-head text-base">FY15 historical · FY27–FY35 projection</h2>
          </div>
        </div>
        <div className="card-body">
          <div className="h-[360px]">
            <ResponsiveContainer width="100%" height="100%">
              <LineChart data={chartData} margin={{ top: 10, right: 24, bottom: 8, left: 0 }}>
                <CartesianGrid strokeDasharray="2 4" stroke="#101A4C20" />
                <XAxis
                  dataKey="fiscalYear"
                  tick={{ fill: '#101A4C', fontSize: 12 }}
                  tickFormatter={(fy) => fyLabel(Number(fy))}
                  stroke="#101A4C40"
                />
                <YAxis
                  tick={{ fill: '#101A4C', fontSize: 12 }}
                  tickFormatter={(v) => `$${(v / 1_000_000).toFixed(0)}M`}
                  stroke="#101A4C40"
                  width={64}
                />
                <Tooltip
                  contentStyle={{
                    background: 'white',
                    border: '1px solid #101A4C20',
                    borderRadius: 8,
                    fontFamily: 'Noto Serif, serif',
                  }}
                  formatter={(v) => millions(Number(v))}
                  labelFormatter={(fy) => `FY${String(fy).slice(-2)}`}
                />
                <Legend wrapperStyle={{ paddingTop: 8 }} />
                <Line
                  type="monotone"
                  dataKey="Historical"
                  stroke={SCENARIO_COLORS.Historical}
                  strokeWidth={2.5}
                  dot={false}
                  connectNulls={false}
                />
                <Line
                  type="monotone"
                  dataKey="Base"
                  stroke={SCENARIO_COLORS.Base}
                  strokeWidth={2.5}
                  dot={{ r: 3 }}
                  connectNulls={false}
                />
                <Line
                  type="monotone"
                  dataKey="Optimistic"
                  stroke={SCENARIO_COLORS.Optimistic}
                  strokeWidth={2.5}
                  dot={{ r: 3 }}
                  connectNulls={false}
                />
                <Line
                  type="monotone"
                  dataKey="Pessimistic"
                  stroke={SCENARIO_COLORS.Pessimistic}
                  strokeWidth={2.5}
                  strokeDasharray="6 4"
                  dot={{ r: 3 }}
                  connectNulls={false}
                />
              </LineChart>
            </ResponsiveContainer>
          </div>
        </div>
      </section>

      {/* Mission-bridge cards — translates the financial scenarios into scholars-served outcomes.
          The Bridgespan dual-bottom-line view: this is what a board votes ON, not ledger lines. */}
      <section className="card">
        <div className="card-header flex items-center justify-between flex-wrap gap-3">
          <div>
            <div className="eyebrow">Mission bridge</div>
            <h2 className="font-head text-base">
              Scholars served · FY27 goal {inputs.scholarGoal[0] ?? 0} · FY32 goal {goalFY32}
            </h2>
          </div>
        </div>
        <div className="card-body grid grid-cols-1 md:grid-cols-3 gap-4">
          {bridgeSummaries.map(({ scenario: s, summary }) => {
            const fy32Pct = goalFY32 > 0 ? summary.fy32Served / goalFY32 : 0;
            const onGoal = fy32Pct >= 1;
            return (
              <div
                key={s}
                className="rounded-lg border border-navy/15 bg-white px-4 py-3 space-y-1"
              >
                <div className="flex items-center justify-between">
                  <div className="eyebrow">{s} scenario</div>
                  <span
                    className={`pill gap-1 ${
                      onGoal ? 'pill-green' : fy32Pct >= 0.85 ? 'pill-yellow' : 'pill-red'
                    }`}
                    aria-label={`FY32 attainment ${percent(fy32Pct, 0)}`}
                  >
                    <span aria-hidden="true">{onGoal ? '●' : fy32Pct >= 0.85 ? '▲' : '✕'}</span>
                    {percent(fy32Pct, 0)} of FY32 goal
                  </span>
                </div>
                <Stat label="FY32 scholars served" value={summary.fy32Served.toLocaleString()} />
                <Stat label="FY35 scholars served" value={summary.fy35Served.toLocaleString()} />
                <Stat
                  label="Cumulative FY27–FY35"
                  value={summary.cumulativeServed.toLocaleString()}
                />
                <Stat
                  label="Years at/above goal"
                  value={`${summary.yearsAtOrAboveGoal} / ${active.years.length}`}
                />
                {(() => {
                  const sScenario = scenarios.find((sc) => sc.scenario === s)!;
                  const avgProgRatio =
                    sScenario.years.reduce((acc, y) => acc + y.programRatio, 0) /
                    sScenario.years.length;
                  const cls = avgProgRatio >= PROGRAM_RATIO_FLOOR ? 'text-emerald-700' : 'text-rose-700';
                  return (
                    <div className="flex items-baseline justify-between gap-3 border-b border-navy/5 pb-1 last:border-b-0">
                      <span className="text-navy/70 text-xs uppercase tracking-wide">
                        Avg program ratio
                      </span>
                      <span className={`font-semibold num ${cls}`}>
                        {percent(avgProgRatio, 1)}
                      </span>
                    </div>
                  );
                })()}
              </div>
            );
          })}
        </div>
      </section>

      <section className="card">
        <div className="card-header flex items-center justify-between">
          <div>
            <div className="eyebrow">Financial overview</div>
            <h2 className="font-head text-base">
              {scenario} scenario · FY27 – FY35
              {viewMode === 'real' && (
                <span className="ml-2 text-xs font-sub font-normal text-purple normal-case tracking-normal">
                  · displayed in real (FY27 $) terms
                </span>
              )}
            </h2>
          </div>
          <div className="flex items-center gap-2">
            {(['Base', 'Optimistic', 'Pessimistic'] as ScenarioName[]).map((s) => (
              <button
                key={s}
                onClick={() => setScenario(s)}
                className={`tab-btn ${scenario === s ? 'tab-btn-active' : ''}`}
              >
                {s}
              </button>
            ))}
          </div>
        </div>
        <div className="card-body overflow-x-auto">
          <table className="w-full text-sm num">
            <thead>
              <tr className="text-navy/60 uppercase text-xs tracking-wider">
                <th className="text-left py-2 pr-4 font-semibold">Financial metric</th>
                {active.years.map((y) => (
                  <th key={y.fiscalYear} className="text-right px-3 py-2 font-semibold">
                    {fyLabel(y.fiscalYear)}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {rowDefs.map((row) => (
                <tr
                  key={row.key}
                  className={
                    row.emphasis
                      ? 'bg-tan/60 border-y-2 border-navy/80 font-semibold'
                      : 'border-b border-navy/5'
                  }
                >
                  <td className="text-left py-2 pr-4 text-navy">{row.label}</td>
                  {active.years.map((y) => {
                    const raw = (y as never)[row.key] as number;
                    return (
                      <td key={y.fiscalYear} className="text-right px-3 py-2 text-navy">
                        {row.format ? row.format(raw) : dollars(raw)}
                      </td>
                    );
                  })}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        <div className="card-body border-t border-navy/10 text-xs text-navy/70 font-sub">
          <p className="font-semibold mb-1 text-navy">Key assumptions</p>
          <ul className="list-disc list-inside space-y-0.5">
            <li>Award costs step down: $5.4M FY27 → $4.5M FY28 → $4.0M FY29, settling $4.0–4.3M.</li>
            <li>Operating expenses grow 1.5%/year with a one-time $500K reduction in FY29 (lease end).</li>
            <li>FY26 ending endowment of $100M reflects major gift, fundraising, and market growth.</li>
            <li>All projections subject to market conditions and successful execution of cost plan.</li>
          </ul>
        </div>
      </section>
    </div>
  );
}

/** Inline stat row used in the Mission-bridge cards. */
function Stat({ label, value }: { label: string; value: string }) {
  return (
    <div className="flex items-baseline justify-between gap-3 border-b border-navy/5 pb-1 last:border-b-0">
      <span className="text-navy/70 text-xs uppercase tracking-wide">{label}</span>
      <span className="font-semibold num text-navy">{value}</span>
    </div>
  );
}

/** Row wrapper for the Board-summary table — keeps left label cell consistent. */
function SummaryRow({
  label,
  children,
}: {
  label: string;
  children: ReactNode;
}) {
  return (
    <tr className="border-b border-navy/5 hover:bg-tan/30">
      <td className="text-left py-2 pr-4 text-navy text-xs">{label}</td>
      {children}
    </tr>
  );
}

/**
 * Translate scenario state into a board-action recommendation. Anchors on
 * Pessimistic + MC P(insolvency) since that's the "what does our floor cost
 * us" view. Returns severity + headline + rationale + concrete actions.
 */
function computeRecommendation(args: {
  pessFY35: number;
  pessMin: number;
  boardFloor: number;
  probAlways: number;
  probInsolv: number;
  pessFirstBelow?: number;
}): {
  severity: ActionSeverity;
  headline: string;
  rationale: ReactNode;
  actions: ReactNode[];
} {
  const { pessFY35, pessMin, boardFloor, probAlways, probInsolv, pessFirstBelow } = args;

  // Urgent: pessimistic breaches the floor OR insolvency probability is meaningful.
  if (probInsolv >= 0.05 || pessMin < 0) {
    return {
      severity: 'urgent',
      headline: `Board action required — pessimistic case shows ${pessMin < 0 ? 'insolvency' : 'high tail risk'} by FY${String(pessFirstBelow ?? 35).slice(-2)}`,
      rationale: (
        <>
          Under the Pessimistic scenario, minimum endowment falls to{' '}
          <strong>{millions(pessMin)}</strong> (vs. the {millions(boardFloor)} floor). Monte Carlo
          shows <strong>{percent(probInsolv, 1)}</strong> of paths reach insolvency. This is above
          the threshold the Finance Committee should accept without explicit response.
        </>
      ),
      actions: [
        'Convene the Finance + Investment Committees within the next quarter to review spending policy and corpus floor.',
        'Authorize a contingency plan: under what trigger does the Board redesignate quasi-endowment to operating reserve?',
        'Stress-test fundraising response — could a rapid major-gifts campaign close the implied gap?',
      ],
    };
  }

  // Watch: pessimistic dips below floor mid-window OR P(stayed-above-floor) below 85%.
  if (pessFirstBelow !== undefined || probAlways < 0.85) {
    return {
      severity: 'watch',
      headline: `Watch — pessimistic case dips below the ${millions(boardFloor)} floor before recovery`,
      rationale: (
        <>
          Pessimistic FY35 ends at <strong>{millions(pessFY35)}</strong>, but the path crosses below{' '}
          {millions(boardFloor)} mid-window
          {pessFirstBelow ? ` (first breach FY${String(pessFirstBelow).slice(-2)})` : ''}. Monte
          Carlo shows{' '}
          <strong>{percent(probAlways, 0)}</strong> of paths stay above the floor every year.
          Recoverable, but worth a Finance Committee read.
        </>
      ),
      actions: [
        'Flag this scenario for the next Finance Committee meeting; brief the rationale.',
        'Confirm the inputs that drive this — fundraising pace, award costs, market assumption.',
        'Consider: would a 50bps reduction in policy spend rate avoid the breach without compromising program?',
      ],
    };
  }

  // On-track: pessimistic stays above the floor every year.
  return {
    severity: 'on-track',
    headline: `On track — pessimistic case stays above the ${millions(boardFloor)} floor`,
    rationale: (
      <>
        Even under Pessimistic, FY35 ends at <strong>{millions(pessFY35)}</strong> with a minimum of{' '}
        <strong>{millions(pessMin)}</strong>. Monte Carlo P(stayed ≥ floor every year) ={' '}
        <strong>{percent(probAlways, 0)}</strong>. The current plan is defensible at the Finance
        Committee level under reasonable stress.
      </>
    ),
    actions: [
      'Annual review at the Finance Committee. No structural change required this cycle.',
      'Maintain quarterly tracking against Pessimistic to confirm reality is not bending downward.',
    ],
  };
}
