// DC CAP financial model — FY27 baseline.
// Pure functions. No DOM, no React. Fully unit-testable.
//
// Window: FY27 → FY35 (9 years). Historical chart context: FY15 → FY26.
// All monetary values are stored in dollars (not millions). UI converts at the boundary.

export type ScenarioName = 'Base' | 'Optimistic' | 'Pessimistic';

/**
 * FASB ASU 2016-14 net-asset classification, simplified for projection use.
 * The legal/audit categories are "with donor restrictions" and "without donor
 * restrictions"; within "without," boards can designate a quasi-endowment.
 * - Restricted: donor-restricted endowment (corpus must remain; only
 *   distribution per donor intent, governed by UPMIFA prudence factors).
 * - Quasi-endowment: board-designated; functions like an endowment until the
 *   board lifts the designation. Earns market return like restricted.
 * - Operating reserve: fully liquid; receives fundraising + distributions,
 *   pays expenses. Best-practice target = 3–6 months of operating expenses
 *   (Nonprofit Operating Reserves Initiative).
 */
export interface NetAssetClassification {
  restricted: number;
  quasiEndowment: number;
  operatingReserve: number;
}

/**
 * Endowment spending-policy configuration. When `enabled` is true, the tool
 * computes a smoothed annual distribution (industry-standard 3-year trailing
 * average × policy rate) and surfaces it alongside the actual cash need.
 * UPMIFA-aligned smoothing damps the year-to-year program volatility a
 * single-year spend rate exposes.
 */
export interface SpendingPolicy {
  enabled: boolean;
  /** Policy rate, e.g., 0.045 = 4.5%. Applied to the smoothed average balance. */
  rate: number;
  /** Trailing window in fiscal years (3 ≈ 12 quarters; industry default). */
  smoothingYears: number;
  /** Buckets the policy applies to. "restrictedAndQuasi" is the most common. */
  appliesTo: 'restrictedOnly' | 'restrictedAndQuasi';
}

export interface PhilanthropicYear {
  /** Locked, signed gifts and pledges already counted as revenue. */
  committed: number;
  /** Reasonable likelihood — renewals from existing donors, late-stage proposals. */
  likely: number;
  /** Unfilled portion of the fundraising target. The "to-find" closing problem. */
  gap: number;
}

export interface FinancialInputs {
  /** Beginning endowment for the first year of the projection window (FY27). */
  beginningEndowment: number;
  /** Award costs target by year (FY27 → FY35), in dollars. */
  awardCosts: number[];
  /** Operating expense target for FY27 (subsequent years grow at opExpensesGrowth). */
  opExpensesInit: number;
  /** Annual operating expense growth rate, percent (e.g., 1.5 means 1.5%). */
  opExpensesGrowth: number;
  /** One-time op-expense reduction year (1-indexed). FY27=1, FY28=2, FY29=3, etc. */
  opExpensesReductionYear: number;
  /** One-time op-expense reduction amount, in dollars. */
  opExpensesReductionAmount: number;
  /** Total fundraising target by year (FY27 → FY35), in dollars. */
  fundraising: number[];
  /** Per-year philanthropic decomposition. Length matches projection window. */
  philanthropic: PhilanthropicYear[];
  /** Annual market return assumptions per scenario, percent. Length matches window. */
  marketReturn: Record<ScenarioName, number[]>;
  /**
   * Average award size per scholar, by year (FY27 → FY35), in dollars. Used to
   * translate award costs into scholars served (awardCosts[i] / awardSize[i]).
   * Per Preston (2026-04-28): $8,000 today, declining to ~$6,000 going forward.
   * The scholars-served bridge is the mission-outcome layer — Bridgespan-style
   * dual-bottom-line view answering "how many scholars do we serve in scenario X?"
   */
  awardSize: number[];
  /**
   * Scholar-count goal by year (FY27 → FY35), used as a reference line on the
   * Mission tab. Per Preston (2026-04-28): goal = 550 scholars by FY32.
   * Default is a flat 550 across the window — a constant goal-state target.
   * Editable per year if the strategic plan ramps the target.
   */
  scholarGoal: number[];
  /**
   * FY27 net-asset split. Total should equal beginningEndowment; minor
   * rounding tolerated. Per Preston (2026-04-28): $40M restricted; the
   * remaining $60M splits between quasi-endowment and operating reserve
   * (default split: $54M quasi / $6M reserve, ≈6 months of expenses).
   */
  netAssets: NetAssetClassification;
  /**
   * Spending-policy configuration. Default is `enabled: false` — the existing
   * "everything is one bucket" projection — to preserve backward compatibility
   * with the math audit's hand-checked baseline. Toggle on to display the
   * UPMIFA-style smoothed distribution and the implied operating-reserve flow.
   */
  spendingPolicy: SpendingPolicy;
  /**
   * Per-year CPI/inflation assumption (percent). Default 2.5 (PCE forecast).
   * Used to deflate nominal projections to real (FY27 baseline) dollars when
   * the user toggles the Real view in the header. Model arithmetic remains
   * nominal — deflation is a display transformation only.
   *
   * Why this matters: the 4.5% sustainable spend rate is conventionally a
   * REAL rate (after inflation). At 2.5% CPI, the equivalent nominal
   * sustainable is ~7%. UPMIFA prudence factor #4 ("expected inflation")
   * requires this be made explicit.
   */
  inflation: number[];
  /**
   * Functional-expense split per Form 990 Part IX. Three categories that must
   * sum to 1.0: Program, Management & General, Fundraising. Used to decompose
   * the single opExpenses line into the IRS-mandated functional view a
   * board/auditor expects to see. Default ratios are typical-scholarship-org:
   * 75% program, 15% M&G, 10% fundraising. Charity Navigator floor: program ≥ 65%.
   */
  opExpenseSplit: FunctionalExpenseSplit;
  /**
   * Asset-class portfolio model. When `enabled`, surfaces portfolio expected
   * return + std-dev computed from the allocation. The "Apply to MC" action
   * populates inputs.marketReturn (Base flat at portfolio mean) and is the
   * SOTA replacement for the single-number return assumption.
   */
  portfolio: AssetClassPortfolio;
}

export interface FunctionalExpenseSplit {
  /** Program services (direct mission delivery). Goal: ≥ 65% per Charity Navigator. */
  program: number;
  /** Management & general (overhead, admin). */
  mgmtGeneral: number;
  /** Fundraising (cost of raising the next dollar). */
  fundraising: number;
}

// ============================================================================
// Asset-class portfolio model (NACUBO-Commonfund / Cambridge Associates style)
// ============================================================================
//
// Replaces the "single annual return" assumption with a 3-asset-class model:
// Equity / Fixed Income / Alternatives. User edits weights, expected returns,
// std-devs, and a 3x3 correlation matrix. The model computes portfolio
// expected return (weighted sum) and portfolio std-dev (sqrt(w' Σ w)). User
// can apply these to the deterministic scenarios + Monte Carlo.

export interface AssetClass {
  key: 'equity' | 'fixedIncome' | 'alternatives';
  label: string;
  /** Portfolio weight (0–1). Should sum to 1 across classes. */
  weight: number;
  /** Annualized expected return, percent. */
  expectedReturn: number;
  /** Annualized std-dev of return, percent. */
  stdDev: number;
}

export interface AssetClassPortfolio {
  enabled: boolean;
  classes: AssetClass[];
  /** 3×3 symmetric correlation matrix. [i][j] = correlation between class i and j.
   *  Diagonal must be 1; off-diagonals in [-1, 1]. */
  correlations: number[][];
}

/** Cambridge Associates / NACUBO-style 60/25/15 default for a $100M endowment.
 *  Returns calibrated to April 2026 vintage capital-market assumptions. */
export const DEFAULT_PORTFOLIO: AssetClassPortfolio = {
  enabled: false,
  classes: [
    { key: 'equity', label: 'Public + private equity', weight: 0.60, expectedReturn: 7.5, stdDev: 16.0 },
    { key: 'fixedIncome', label: 'Fixed income', weight: 0.25, expectedReturn: 4.0, stdDev: 5.5 },
    { key: 'alternatives', label: 'Alternatives (HF, real assets)', weight: 0.15, expectedReturn: 6.0, stdDev: 10.0 },
  ],
  // Default correlations: equity-fixed weakly negative (-0.1 reflects diversification),
  // equity-alts moderate positive (0.5), fixed-alts low (0.2). Cambridge Associates norms.
  correlations: [
    [1.0, -0.1, 0.5],
    [-0.1, 1.0, 0.2],
    [0.5, 0.2, 1.0],
  ],
};

/** Portfolio expected return = Σ wi × ri. */
export function portfolioExpectedReturn(p: AssetClassPortfolio): number {
  return p.classes.reduce((acc, c) => acc + c.weight * c.expectedReturn, 0);
}

/** Portfolio std-dev = sqrt(w' Σ w) where Σ_ij = ρ_ij × σ_i × σ_j. */
export function portfolioStdDev(p: AssetClassPortfolio): number {
  let variance = 0;
  for (let i = 0; i < p.classes.length; i++) {
    for (let j = 0; j < p.classes.length; j++) {
      const cov =
        (p.correlations[i]?.[j] ?? 0) * p.classes[i].stdDev * p.classes[j].stdDev;
      variance += p.classes[i].weight * p.classes[j].weight * cov;
    }
  }
  return Math.sqrt(Math.max(0, variance));
}

export interface YearMetrics {
  fiscalYear: number;
  beginningEndowment: number;
  fundraising: number;
  marketReturn: number;
  totalIncome: number;
  awardCosts: number;
  /** Computed: awardCosts / awardSize. Floor of 0; rounded to nearest scholar. */
  scholarsServed: number;
  /** Per-year scholar-count goal from inputs.scholarGoal[i]. */
  scholarGoal: number;
  /** scholarsServed / scholarGoal, expressed as a fraction. 1.0 = on-target. */
  scholarGoalAttainment: number;
  opExpenses: number;
  totalExpenses: number;
  totalPL: number;
  endingEndowment: number;
  /**
   * Net draw on the endowment as a fraction of beginning endowment.
   * Defined as (totalExpenses − fundraising) / beginningEndowment.
   * This is the standard endowment-policy benchmark (4.5% sustainable, etc.) —
   * fundraising offsets operating costs before any draw on the endowment.
   * Negative values mean the year was a net contributor to the endowment (good).
   */
  spendRate: number;
  /**
   * Smoothed-policy distribution from restricted (+ quasi if configured) per
   * spendingPolicy. Computed from the trailing N-year average of beg-of-year
   * balances × policy rate. Always populated — when policy is disabled, this
   * is informational only; when enabled, the UI shows it alongside actual draw.
   */
  policyDistribution: number;
  /**
   * Effective draw the org actually needs from operating reserve / endowment
   * to cover expenses: max(0, totalExpenses − fundraising). Compare against
   * policyDistribution: surplus = sustainable; deficit = deficit-spending the
   * board needs to authorize or close via fundraising.
   */
  policyDistributionGap: number;
  /**
   * Operating-reserve balance at year-end, projected forward from FY27.
   * Logic: opReserve(i) = opReserve(i-1) + fundraising(i) + policyDistribution(i)
   *                       − totalExpenses(i). Persistent draw signals
   *                       reserve depletion (going-concern flag).
   */
  operatingReserveEnd: number;
  /**
   * Functional-expense decomposition of opExpenses per Form 990 Part IX.
   * Each is opExpenses × the corresponding split ratio.
   */
  opProgram: number;
  opMgmtGeneral: number;
  opFundraising: number;
  /**
   * Program-services ratio: (awardCosts + opProgram) / totalExpenses. The
   * board-facing "what % of every dollar reaches mission" number that funders
   * and Charity Navigator cite. Goal ≥ 0.65.
   */
  programRatio: number;
}

export interface ScenarioProjection {
  scenario: ScenarioName;
  years: YearMetrics[];
}

