// Charity Navigator: program services ratio ≥ 0.65 = "exceptional."
export const PROGRAM_RATIO_FLOOR = 0.65;

// --- Helpers ---

export function fiscalYears(): number[] {
  const out: number[] = [];
  for (let y = PROJECTION_START_FY; y <= PROJECTION_END_FY; y++) out.push(y);
  return out;
}

/**
 * Compute operating expenses for a given year index (0-based) using iterative
 * compounding. Critical: when the one-time reduction kicks in (e.g., FY29 lease
 * end), the lower base persists — all subsequent years compound from the cut
 * value. This matches the original Shiny model and matches reality for a
 * permanent structural cost reduction.
 */
export function opExpensesAtYear(
  yearIdx: number,
  init: number,
  growthPct: number,
  reductionYear: number,
  reductionAmount: number
): number {
  // Reduction at year 1 hits init directly; later reductions hit after the
  // growth step that produces that year's value.
  let val = reductionYear === 1 ? init - reductionAmount : init;
  for (let i = 1; i <= yearIdx; i++) {
    val = val * (1 + growthPct / 100);
    if (i + 1 === reductionYear) val -= reductionAmount;
  }
  return val;
}

/**
 * Roll one scenario forward across the projection window. Pure: takes inputs,
 * returns fully-populated YearMetrics for each year.
 */
export function projectScenario(
  inputs: FinancialInputs,
  scenario: ScenarioName
): ScenarioProjection {
  const years = fiscalYears();
  const out: YearMetrics[] = [];
  let beg = inputs.beginningEndowment;

  // Spending-policy bookkeeping: track the trailing-N-year window of
  // beginning-of-year balances (for the policy-applicable buckets) so we can
  // compute the smoothed distribution. We use beginning-of-year because that's
  // what UPMIFA / NACUBO conventions reference (the value at the start of the
  // distribution period).
  const policy = inputs.spendingPolicy;
  const policyAppliesToQuasi = policy.appliesTo === 'restrictedAndQuasi';
  const begRestricted = inputs.netAssets?.restricted ?? 0;
  const begQuasi = inputs.netAssets?.quasiEndowment ?? 0;
  // Initial pool that the policy rate applies against (restricted, optionally + quasi):
  const initialPolicyPool = begRestricted + (policyAppliesToQuasi ? begQuasi : 0);
  // For smoothing, we need a rolling window of those pool balances. We seed
  // it with the FY27 starting pool repeated so that year-1 distribution is
  // simply rate × pool (no synthetic ramp).
  const policyWindow: number[] = Array(Math.max(1, policy.smoothingYears)).fill(initialPolicyPool);

  // Operating-reserve bookkeeping. When policy disabled, reserve is purely
  // informational — it's still tracked so the UI can show the implied flow.
  let opReserve = inputs.netAssets?.operatingReserve ?? 0;
  // The pool grows with the same market return as the rest of the endowment
  // (it's all invested) — but we model it as a single "pool balance" that
  // grows; the bucket split is FY27-only-information for display.
  let policyPool = initialPolicyPool;

  for (let i = 0; i < years.length; i++) {
    const fy = years[i];
    const fundraising = inputs.fundraising[i] ?? 0;
    const awardCosts = inputs.awardCosts[i] ?? 0;
    const opExpenses = opExpensesAtYear(
      i,
      inputs.opExpensesInit,
      inputs.opExpensesGrowth,
      inputs.opExpensesReductionYear,
      inputs.opExpensesReductionAmount
    );
    const totalExpenses = awardCosts + opExpenses;
    const returnPct = inputs.marketReturn[scenario][i] ?? 0;
    const marketReturn = beg * (returnPct / 100);
    const totalIncome = fundraising + marketReturn;
    const totalPL = totalIncome - totalExpenses;
    const endingEndowment = beg + totalPL;
    // Net draw on endowment = (expenses − fundraising) / beginning endowment.
    // Standard endowment-policy benchmark (e.g., 4.5% sustainable spend rate).
    // Fundraising offsets operating costs before any principal draw.
    const netDraw = totalExpenses - fundraising;
    const spendRate = beg > 0 ? netDraw / beg : 0;

    // Scholars-served bridge — derived metric, no model state. Award costs
    // ÷ avg award size = scholars funded that year. Goal attainment is a fraction.
    const awardSize = inputs.awardSize?.[i] ?? 6000;
    const scholarGoal = inputs.scholarGoal?.[i] ?? 0;
    const scholarsServed = awardSize > 0 ? Math.max(0, Math.round(awardCosts / awardSize)) : 0;
    const scholarGoalAttainment = scholarGoal > 0 ? scholarsServed / scholarGoal : 0;

    // Spending-policy distribution: rate × trailing N-year average of the
    // policy-applicable pool. Computed every year regardless of whether the
    // policy is "enabled" — informational either way; UI gates the display.
    const trailingAvgPool =
      policyWindow.reduce((acc, v) => acc + v, 0) / policyWindow.length;
    const policyDistribution = policy.rate * trailingAvgPool;
    const actualDraw = Math.max(0, totalExpenses - fundraising);
    const policyDistributionGap = actualDraw - policyDistribution;

    // Operating-reserve flow (single-pool simplification):
    //   reserveEnd = reserveBeg + fundraising + policyDistribution − totalExpenses
    // Equivalent to reserveBeg − (actualDraw − policyDistribution) = reserveBeg − gap.
    // Negative reserveEnd is the going-concern flag.
    const operatingReserveEnd = opReserve + fundraising + policyDistribution - totalExpenses;

    // Functional-expense decomposition per Form 990 Part IX. The split is a
    // composition over opExpenses (not totalExpenses) — awardCosts are
    // already-program by definition (direct scholarship outlays).
    const split = inputs.opExpenseSplit ?? { program: 0.75, mgmtGeneral: 0.15, fundraising: 0.10 };
    const opProgram = opExpenses * split.program;
    const opMgmtGeneral = opExpenses * split.mgmtGeneral;
    const opFundraising = opExpenses * split.fundraising;
    const programTotal = awardCosts + opProgram;
    const programRatio = totalExpenses > 0 ? programTotal / totalExpenses : 0;

    out.push({
      fiscalYear: fy,
      beginningEndowment: beg,
      fundraising,
      marketReturn,
      totalIncome,
      awardCosts,
      scholarsServed,
      scholarGoal,
      scholarGoalAttainment,
      opExpenses,
      totalExpenses,
      totalPL,
      endingEndowment,
      spendRate,
      policyDistribution,
      policyDistributionGap,
      operatingReserveEnd,
      opProgram,
      opMgmtGeneral,
      opFundraising,
      programRatio,
    });

    // Roll forward: pool grows with market return (same as overall endowment),
    // less the distribution that flowed out of it. Operating reserve is what
    // we computed. Window slides one year forward.
    policyPool = policyPool * (1 + returnPct / 100) - policyDistribution;
    policyWindow.shift();
    policyWindow.push(policyPool);
    opReserve = operatingReserveEnd;

    beg = endingEndowment;
  }

  return { scenario, years: out };
}

/** Run all three scenarios. */
export function projectAllScenarios(inputs: FinancialInputs): ScenarioProjection[] {
  return (['Base', 'Optimistic', 'Pessimistic'] as ScenarioName[]).map((s) =>
    projectScenario(inputs, s)
  );
}

/**
 * Compute cumulative inflation factors per year given an annual CPI series.
 * cumInflation[i] is the multiplier from FY27 dollars to FY(27+i) dollars.
 * Example: [2.5, 2.5, 2.5, ...] → [1.025, 1.05^something, ...]
 *
 * Convention: cumInflation[0] = 1 + cpi[0]/100, i.e., FY27's inflation has
 * already happened by the END of FY27. To deflate FY27's ending balance back
 * to FY27 START dollars, divide by cumInflation[0]. To deflate FY28's end
 * balance to FY27 dollars, divide by cumInflation[1] = (1+cpi[0])(1+cpi[1])/100².
 */
export function cumulativeInflationFactors(cpi: number[]): number[] {
  const out: number[] = [];
  let running = 1;
  for (let i = 0; i < cpi.length; i++) {
    running *= 1 + (cpi[i] ?? 0) / 100;
    out.push(running);
  }
  return out;
}

/**
 * Return a copy of the projection with all dollar-denominated metrics deflated
 * to FY27 (real) dollars. Ratios and counts (spendRate, scholarsServed,
 * scholarGoalAttainment, marketReturn % implied) are passed through unchanged.
 *
 * Display-only transformation — model arithmetic remains in nominal $.
 */
export function deflateProjection(
  proj: ScenarioProjection,
  cumInflation: number[]
): ScenarioProjection {
  const deflated = proj.years.map((y, i) => {
    const f = cumInflation[i] ?? 1;
    if (f === 0) return y;
    return {
      ...y,
      beginningEndowment: y.beginningEndowment / f,
      fundraising: y.fundraising / f,
      marketReturn: y.marketReturn / f,
      totalIncome: y.totalIncome / f,
      awardCosts: y.awardCosts / f,
      opExpenses: y.opExpenses / f,
      totalExpenses: y.totalExpenses / f,
      totalPL: y.totalPL / f,
      endingEndowment: y.endingEndowment / f,
      policyDistribution: y.policyDistribution / f,
      policyDistributionGap: y.policyDistributionGap / f,
      operatingReserveEnd: y.operatingReserveEnd / f,
      opProgram: y.opProgram / f,
      opMgmtGeneral: y.opMgmtGeneral / f,
      opFundraising: y.opFundraising / f,
      // Ratios and counts unchanged: spendRate, scholarsServed, scholarGoal,
      // scholarGoalAttainment, programRatio.
    };
  });
  return { scenario: proj.scenario, years: deflated };
}

// ============================================================================
// Liquidity coverage (ASU 2014-15 going-concern, NRO operating reserve)
// ============================================================================
//
// "Months of operating expenses available" — the question a CFO/Treasurer
// asks first when stress-testing. Conservative answer counts only liquid
// operating reserve; SOTA answer includes board-designated quasi-endowment
// (which can be liquidated — board can lift the designation, but with
// signaling/governance cost). Both views reported.
//
// Bands: <3 mo = ASU 2014-15 substantial-doubt threshold (red). 3–6 mo =
// NRO best-practice minimum band (amber). 6–12 mo = healthy (green).
// 12+ mo = strong (green).

export const LIQUIDITY_MIN_MONTHS = 3;
export const LIQUIDITY_HEALTHY_MONTHS = 6;
export type LiquidityBand = 'red' | 'amber' | 'green';

export function liquidityBand(months: number): LiquidityBand {
  if (months < LIQUIDITY_MIN_MONTHS) return 'red';
  if (months < LIQUIDITY_HEALTHY_MONTHS) return 'amber';
  return 'green';
}

export interface LiquidityYear {
  fiscalYear: number;
  /** Operating-reserve balance at year-end. */
  operatingReserveEnd: number;
  /** (operatingReserveEnd + quasiLiquidationFactor × initial quasi) / monthlyExpense. */
  totalLiquidMonths: number;
  /** Operating reserve only (conservative). */
  reserveOnlyMonths: number;
  /** Monthly operating expense at this year (totalExpenses / 12). */
  monthlyExpense: number;
}

/**
 * Project liquidity coverage year by year using the projection's operating-
 * reserve flow. The quasi pool is held constant at its FY27 value ×
 * liquidationFactor for simplicity — a real model would accrete quasi with
 * market return and shrink it with any liquidation events.
 *
 * @param liquidationFactor — fraction of quasi-endowment treated as liquid
 *   (default 1.0: board can fully designate to operating). Set 0 for the
 *   strictest reserve-only view; set 0.5 for "half could be unwound in 6 mo."
 */
export function projectLiquidity(
  proj: ScenarioProjection,
  inputs: FinancialInputs,
  liquidationFactor = 1.0
): LiquidityYear[] {
  const liquidQuasi = inputs.netAssets.quasiEndowment * liquidationFactor;
  return proj.years.map((y) => {
    const monthlyExpense = y.totalExpenses / 12;
    const reserveOnly = monthlyExpense > 0 ? y.operatingReserveEnd / monthlyExpense : 0;
    const total =
      monthlyExpense > 0 ? (y.operatingReserveEnd + liquidQuasi) / monthlyExpense : 0;
    return {
      fiscalYear: y.fiscalYear,
      operatingReserveEnd: y.operatingReserveEnd,
      monthlyExpense,
      reserveOnlyMonths: reserveOnly,
      totalLiquidMonths: total,
    };
  });
}

// ============================================================================
// Goal-seek (inverse mode)
// ============================================================================
//
// Given a target outcome — e.g., "FY32 scholars ≥ 550" — solve for the value
// of a single input variable that achieves it, holding all other inputs fixed.
// Implementation: monotonic bisection over a user-provided search range.
// Limitations:
//  - Single-variable only (no joint optimization). For "what mix of fundraising
//    AND return achieves target," we'd need a 2-D solver — out of MVP scope.
//  - Assumes monotonic relationship between variable and metric. Variables
//    chosen below all satisfy this for the metrics offered.
//  - Deterministic metrics only (no P(insolvency) — that requires MC and is
//    unstable under bisection due to sampling noise).

export type GoalSeekVariable =
  | 'fundraisingFlat'
  | 'marketReturnFlat'
  | 'awardSizeFlat'
  | 'beginningEndowment';

export type GoalSeekMetric =
  | 'fy32Scholars'
  | 'fy35Scholars'
  | 'cumulativeScholars'
  | 'fy35Ending'
  | 'minEndowment';

export interface GoalSeekRequest {
  variable: GoalSeekVariable;
  /** Lower bound of search range, in the variable's native unit. */
  lo: number;
  /** Upper bound of search range. */
  hi: number;
  metric: GoalSeekMetric;
  /** Target metric value. */
  target: number;
  scenario: ScenarioName;
  /** Convergence tolerance in metric units (default chosen per metric). */
  tolerance?: number;
  /** Hard cap on iterations (default 60). */
  maxIterations?: number;
}

export interface GoalSeekResult {
  /** True if a value within the search range gets within tolerance of target. */
  found: boolean;
  /** Best variable value found (final midpoint of bisection). */
  variableValue: number;
  /** Metric value at variableValue. */
  achievedMetric: number;
  /** Iterations consumed. */
  iterations: number;
  /** Why we stopped: 'converged' | 'maxIterations' | 'noBracket'. */
  status: 'converged' | 'maxIterations' | 'noBracket';
}

function applyVariable(
  inputs: FinancialInputs,
  variable: GoalSeekVariable,
  v: number
): FinancialInputs {
  const len = inputs.fundraising.length;
  switch (variable) {
    case 'fundraisingFlat':
      return { ...inputs, fundraising: Array(len).fill(v) };
    case 'marketReturnFlat':
      return {
        ...inputs,
        marketReturn: {
          ...inputs.marketReturn,
          Base: Array(len).fill(v),
          Optimistic: Array(len).fill(v + 1.5),
          Pessimistic: inputs.marketReturn.Pessimistic, // leave stress alone
        },
      };
    case 'awardSizeFlat':
      return { ...inputs, awardSize: Array(len).fill(v) };
    case 'beginningEndowment':
      return { ...inputs, beginningEndowment: v };
  }
}

function evaluateMetric(proj: ScenarioProjection, metric: GoalSeekMetric): number {
  const ys = proj.years;
  switch (metric) {
    case 'fy32Scholars':
      return ys.find((y) => y.fiscalYear === 2032)?.scholarsServed ?? 0;
    case 'fy35Scholars':
      return ys[ys.length - 1]?.scholarsServed ?? 0;
    case 'cumulativeScholars':
      return ys.reduce((acc, y) => acc + y.scholarsServed, 0);
    case 'fy35Ending':
      return ys[ys.length - 1]?.endingEndowment ?? 0;
    case 'minEndowment':
      return Math.min(...ys.map((y) => y.endingEndowment));
  }
}

const DEFAULT_TOLERANCE: Record<GoalSeekMetric, number> = {
  fy32Scholars: 1,
  fy35Scholars: 1,
  cumulativeScholars: 5,
  fy35Ending: 100_000,
  minEndowment: 100_000,
};

/**
 * Solve for the variable value that makes the metric equal the target.
 * Bisection assumes monotonicity (which holds for all variable/metric pairs
 * we expose). Returns the closest variable value found within tolerance, or
 * status='noBracket' if the target is not achievable in [lo, hi].
 */
export function goalSeek(
  inputs: FinancialInputs,
  req: GoalSeekRequest
): GoalSeekResult {
  const tol = req.tolerance ?? DEFAULT_TOLERANCE[req.metric];
  const maxIter = req.maxIterations ?? 60;

  let lo = req.lo;
  let hi = req.hi;
  const projAt = (v: number) =>
    projectScenario(applyVariable(inputs, req.variable, v), req.scenario);
  const metricAt = (v: number) => evaluateMetric(projAt(v), req.metric);

  const fLo = metricAt(lo);
  const fHi = metricAt(hi);

  // Bracketing check: target must lie between f(lo) and f(hi). If both are
  // above or both below, target is unreachable in this range.
  const targetInBracket = (fLo - req.target) * (fHi - req.target) <= 0;
  if (!targetInBracket) {
    // Return whichever endpoint is closest as a best-effort answer.
    const closerToLo = Math.abs(fLo - req.target) < Math.abs(fHi - req.target);
    return {
      found: false,
      variableValue: closerToLo ? lo : hi,
      achievedMetric: closerToLo ? fLo : fHi,
      iterations: 1,
      status: 'noBracket',
    };
  }

  let iterations = 0;
  let mid = (lo + hi) / 2;
  let fMid = metricAt(mid);

  while (Math.abs(fMid - req.target) > tol && iterations < maxIter) {
    // Determine which half of the bracket still contains the crossing.
    if ((fLo - req.target) * (fMid - req.target) <= 0) {
      hi = mid;
    } else {
      lo = mid;
    }
    mid = (lo + hi) / 2;
    fMid = metricAt(mid);
    iterations++;
    // Numerical floor: if the bracket has collapsed to machine-precision
    // width, accept the midpoint and stop.
    if (Math.abs(hi - lo) < 1e-9) break;
  }

  return {
    found: Math.abs(fMid - req.target) <= tol,
    variableValue: mid,
    achievedMetric: fMid,
    iterations,
    status:
      Math.abs(fMid - req.target) <= tol ? 'converged' : 'maxIterations',
  };
}

/**
 * Mission-bridge metrics for a projection: cumulative scholars served across the
 * window, average annual count, and the share of years where scholar count met or
 * exceeded the goal. Derived directly from per-year YearMetrics — same numbers,
 * just summarized for top-line stat cards.
 */
export interface ScholarBridgeSummary {
  cumulativeServed: number;
  averageAnnualServed: number;
  yearsAtOrAboveGoal: number;
  fy32Served: number;
  fy35Served: number;
}

export function summarizeScholarBridge(proj: ScenarioProjection): ScholarBridgeSummary {
  const ys = proj.years;
  const cum = ys.reduce((acc, y) => acc + y.scholarsServed, 0);
  const fy32 = ys.find((y) => y.fiscalYear === 2032)?.scholarsServed ?? 0;
  const fy35 = ys[ys.length - 1]?.scholarsServed ?? 0;
  const atGoal = ys.filter((y) => y.scholarGoal > 0 && y.scholarsServed >= y.scholarGoal).length;
  return {
    cumulativeServed: cum,
    averageAnnualServed: ys.length > 0 ? Math.round(cum / ys.length) : 0,
    yearsAtOrAboveGoal: atGoal,
    fy32Served: fy32,
    fy35Served: fy35,
  };
}

// --- Philanthropic decomposition helpers ---

export function philanthropicTotal(p: PhilanthropicYear): number {
  return p.committed + p.likely + p.gap;
}

/**
 * For each projection year, compare the fundraising target to the philanthropic
 * decomposition. If they differ, the UI should surface the variance.
 */
export interface PhilanthropicReconciliation {
  fiscalYear: number;
  target: number;
  committed: number;
  likely: number;
  gap: number;
  total: number;
  variance: number; // total - target. Zero means in sync.
  pctCommitted: number; // committed / target
  pctSecured: number; // (committed + likely) / target
}

export function reconcilePhilanthropic(
  inputs: FinancialInputs
): PhilanthropicReconciliation[] {
  const years = fiscalYears();
  return years.map((fy, i) => {
    const target = inputs.fundraising[i] ?? 0;
    const p = inputs.philanthropic[i] ?? { committed: 0, likely: 0, gap: 0 };
    const total = philanthropicTotal(p);
    return {
      fiscalYear: fy,
      target,
      committed: p.committed,
      likely: p.likely,
      gap: p.gap,
      total,
      variance: total - target,
      pctCommitted: target > 0 ? p.committed / target : 0,
      pctSecured: target > 0 ? (p.committed + p.likely) / target : 0,
    };
  });
}

// --- Spend-rate guardrail thresholds ---

export const SUSTAINABLE_SPEND_RATE = 0.045; // 4.5% — common endowment policy target
export const WARN_SPEND_RATE = 0.06; // 6%+ is a yellow flag
export const ALERT_SPEND_RATE = 0.08; // 8%+ is a red flag

export type SpendRateBand = 'green' | 'yellow' | 'red';

