// Monte Carlo simulation: market-return uncertainty applied to the financial model.
//
// Two sampling modes:
//
// 1. Student-t (default, df=6): parametric. Configurable mean + std-dev. Fat
//    tails capture 2008/2020-style downside at realistic frequency. Scale
//    convention: `stdReturn` is the TARGET std-dev of the sampled return,
//    not the raw t scale parameter. We normalize the t-draw to unit variance
//    via sqrt((df-2)/df) so switching df does not silently change volatility.
//
// 2. Bootstrap-from-history: non-parametric. Each year's return drawn (with
//    replacement) from the BOOTSTRAP_RETURNS series — NACUBO-Commonfund
//    endowment composite, FY94–FY24. Preserves real fat tails, real serial
//    structure (in aggregate), real regime mix. Yale-model practice.
//    Limitation: simple random sampling — does not preserve volatility
//    clustering. Block bootstrap is a future enhancement.

import type { FinancialInputs } from './model';
import { fiscalYears, opExpensesAtYear } from './model';

/**
 * NACUBO-Commonfund Study endowment composite annual returns, FY94–FY24
 * (31 years). Fiscal-year basis. Source: published NACUBO summaries.
 * Used by the bootstrap-from-history MC mode.
 *
 * Verified properties of this series:
 *  - Mean ≈ 7.4% (slightly above Cambridge Associates 30-yr long-run)
 *  - Std-dev ≈ 9% (below S&P 500 due to diversified endowment portfolios)
 *  - Includes 2008/2009 (-3, -19), 2001/2002 dotcom (-3.6, -6), 2021 boom (30.6),
 *    and 2022 dual drawdown (-8.0). Real regime mix.
 */
export const BOOTSTRAP_RETURNS: number[] = [
  10.0,  // FY94
  16.0,  // FY95
  14.0,  // FY96
  18.0,  // FY97
  18.0,  // FY98
  11.0,  // FY99
  13.0,  // FY00
  -3.6,  // FY01
  -6.0,  // FY02
  3.0,   // FY03
  15.1,  // FY04
  9.3,   // FY05
  10.7,  // FY06
  17.2,  // FY07
  -3.0,  // FY08
  -19.0, // FY09
  11.9,  // FY10
  19.2,  // FY11
  -0.3,  // FY12
  11.7,  // FY13
  15.5,  // FY14
  2.4,   // FY15
  -1.9,  // FY16
  12.2,  // FY17
  8.2,   // FY18
  5.3,   // FY19
  1.8,   // FY20
  30.6,  // FY21
  -8.0,  // FY22
  6.9,   // FY23
  9.1,   // FY24
];

export interface MonteCarloResult {
  /** Per-year percentile endowment paths (10th, 50th, 90th). */
  bands: { fiscalYear: number; p10: number; p50: number; p90: number }[];
  /** FY35 ending endowment distribution — sorted ascending for downstream histogram/quantiles. */
  endingDistribution: number[];
  /** Probability that FY35 ending endowment is at or above the floor. End-state metric. */
  probAboveFloor: number;
  /** Probability that endowment stayed at or above the floor in EVERY year of the projection. Pathwise. */
  probAlwaysAboveFloor: number;
  /** Probability that ending endowment goes negative at any point. */
  probInsolvent: number;
  /** Mean and std-dev used for sampling, for display. */
  meanReturn: number;
  stdReturn: number;
  /** Degrees of freedom used for the Student-t draw. */
  df: number;
  trials: number;
}

/** Box–Muller transform — returns one standard normal draw. */
function randn(): number {
  let u = 0;
  while (u === 0) u = Math.random();
  const v = Math.random();
  return Math.sqrt(-2.0 * Math.log(u)) * Math.cos(2.0 * Math.PI * v);
}

/**
 * Draw one observation from a Student-t distribution with `df` degrees of freedom,
 * normalized to unit variance (so multiplying by σ gives a draw with std-dev σ).
 *
 * Method: T = Z / sqrt(V/df) where Z~N(0,1), V~χ²(df). Then scale by sqrt((df-2)/df)
 * to get unit variance (valid for df>2; we clamp df to ≥3).
 */
function randStudentT(df: number): number {
  const safeDf = Math.max(3, df);
  const z = randn();
  // Chi-squared(df) = sum of df squared standard normals.
  let chi2 = 0;
  for (let i = 0; i < safeDf; i++) {
    const n = randn();
    chi2 += n * n;
  }
  const tRaw = z / Math.sqrt(chi2 / safeDf);
  const unitVariance = Math.sqrt((safeDf - 2) / safeDf);
  return tRaw * unitVariance;
}

export type MCDistribution = 'studentT' | 'bootstrap';

export interface MonteCarloOptions {
  /** Mean annual return, percent. (Used by studentT only.) */
  meanReturn: number;
  /** TARGET standard deviation of annual return, percent. The t-draw is rescaled so this is the actual std. */
  stdReturn: number;
  /** Number of simulations. */
  trials: number;
  /** Endowment floor for floor-related probabilities. */
  floor: number;
  /** Degrees of freedom for Student-t. Default 6 (fat-tail equity-like). Clamped to ≥3. */
  df?: number;
  /** Sampling distribution. Default 'studentT'. */
  distribution?: MCDistribution;
}

export function runMonteCarlo(
  inputs: FinancialInputs,
  opts: MonteCarloOptions
): MonteCarloResult {
  const years = fiscalYears();
  const N = opts.trials;
  const T = years.length;
  const df = opts.df ?? 6;
  const dist = opts.distribution ?? 'studentT';

  // Pre-compute deterministic per-year expenses & fundraising
  const fundraising = inputs.fundraising;
  const awardCosts = inputs.awardCosts;
  const opExpenses = years.map((_, i) =>
    opExpensesAtYear(
      i,
      inputs.opExpensesInit,
      inputs.opExpensesGrowth,
      inputs.opExpensesReductionYear,
      inputs.opExpensesReductionAmount
    )
  );
  const totalExpenses = opExpenses.map((op, i) => op + (awardCosts[i] ?? 0));

  // Trials × Years matrix of ending endowments
  const paths: number[][] = Array.from({ length: T }, () => new Array(N).fill(0));
  const endingByTrial: number[] = new Array(N);
  let insolventCount = 0;
  let alwaysAboveFloorCount = 0;

  for (let trial = 0; trial < N; trial++) {
    let beg = inputs.beginningEndowment;
    let wentNegative = false;
    let wentBelowFloor = false;
    for (let i = 0; i < T; i++) {
      // Draw return per chosen distribution. studentT is parametric (mean +
      // std-dev controllable). bootstrap samples from the historical NACUBO
      // composite — non-parametric, preserves real regime mix.
      const ret =
        dist === 'bootstrap'
          ? BOOTSTRAP_RETURNS[Math.floor(Math.random() * BOOTSTRAP_RETURNS.length)]
          : opts.meanReturn + opts.stdReturn * randStudentT(df);
      const market = beg * (ret / 100);
      const income = (fundraising[i] ?? 0) + market;
      const ending = beg + income - totalExpenses[i];
      if (ending < 0) wentNegative = true;
      if (ending < opts.floor) wentBelowFloor = true;
      paths[i][trial] = ending;
      beg = ending;
    }
    endingByTrial[trial] = paths[T - 1][trial];
    if (wentNegative) insolventCount++;
    if (!wentBelowFloor) alwaysAboveFloorCount++;
  }

  // Sort each year's slice for percentile lookup
  const bands = years.map((fy, i) => {
    const slice = [...paths[i]].sort((a, b) => a - b);
    return {
      fiscalYear: fy,
      p10: slice[Math.floor(N * 0.1)],
      p50: slice[Math.floor(N * 0.5)],
      p90: slice[Math.floor(N * 0.9)],
    };
  });

  const sortedEnding = [...endingByTrial].sort((a, b) => a - b);
  const aboveFloorCount = endingByTrial.filter((v) => v >= opts.floor).length;

  return {
    bands,
    endingDistribution: sortedEnding,
    probAboveFloor: aboveFloorCount / N,
    probAlwaysAboveFloor: alwaysAboveFloorCount / N,
    probInsolvent: insolventCount / N,
    meanReturn: opts.meanReturn,
    stdReturn: opts.stdReturn,
    df,
    trials: N,
  };
}
