/**
 * Brief — the default landing for the CEO and Board.
 *
 * Single-screen, 30-second read. Answers four questions:
 *   1. Are we OK financially?
 *   2. What's the worst case?
 *   3. How many scholars do we serve?
 *   4. What do I need to decide?
 *
 * No tables, no editable fields, no per-year detail. The Detail tabs and the
 * inputs panel hold all the depth — Brief is the headline read.
 */
import { useMemo, type ReactNode } from 'react';
import {
  CartesianGrid,
  Line,
  LineChart,
  ResponsiveContainer,
  Tooltip,
  XAxis,
  YAxis,
} from 'recharts';
import type { FinancialInputs } from '../../lib/model';
import {
  HISTORICAL_ENDOWMENT,
  PROGRAM_RATIO_FLOOR,
  SUSTAINABLE_SPEND_RATE,
  deflateProjection,
  liquidityBand,
  projectAllScenarios,
  projectLiquidity,
  summarizeScholarBridge,
} from '../../lib/model';
import { runMonteCarlo } from '../../lib/montecarlo';
import { fyLabel, millions, percent } from '../../lib/format';
import { SCENARIO_COLORS } from '../../lib/colors';
import { RecommendedAction } from '../RecommendedAction';
import type { ActionSeverity } from '../RecommendedAction';

interface Props {
  inputs: FinancialInputs;
  viewMode: 'nominal' | 'real';
  cumInflation: number[];
  /** Quick-edit affordance: opens the (collapsed) inputs panel. */
  onEditAssumptions?: () => void;
}

export function Brief({ inputs, viewMode, cumInflation, onEditAssumptions }: Props) {
  const boardFloor = 40_000_000;

  const nominalScenarios = useMemo(() => projectAllScenarios(inputs), [inputs]);
  const scenarios = useMemo(
    () =>
      viewMode === 'real'
        ? nominalScenarios.map((s) => deflateProjection(s, cumInflation))
        : nominalScenarios,
    [nominalScenarios, viewMode, cumInflation]
  );

  const baseProj = scenarios.find((s) => s.scenario === 'Base')!;
  const optProj = scenarios.find((s) => s.scenario === 'Optimistic')!;
  const pessProj = scenarios.find((s) => s.scenario === 'Pessimistic')!;

  // Single MC pass for the headline P(insolvency) + p10 outcome.
  const mc = useMemo(
    () =>
      runMonteCarlo(inputs, {
        meanReturn: 6.5,
        stdReturn: 12,
        trials: 1000,
        floor: boardFloor,
        df: 6,
      }),
    [inputs]
  );

  // Mission bridge — anchor on Base (the planning case).
  const baseBridge = summarizeScholarBridge(baseProj);
  const goalFY32 = inputs.scholarGoal[5] ?? 550;
  const baseFY32Pct = goalFY32 > 0 ? baseBridge.fy32Served / goalFY32 : 0;

  // Liquidity headline: Pessimistic FY35 reserve-only and +quasi.
  const pessLiquidity = projectLiquidity(pessProj, inputs, 1.0);
  const pessFY35Liq = pessLiquidity[8];

  // Avg net spend rate (Base) for the discipline block.
  const avgSpendBase =
    baseProj.years.reduce((acc, y) => acc + y.spendRate, 0) / baseProj.years.length;

  // Recommendation: same logic as Scenario Overview — anchored on Pess + MC.
  const pessFY35 = pessProj.years[8].endingEndowment;
  const pessTroughEntry = pessProj.years.reduce((acc, y) =>
    y.endingEndowment < acc.endingEndowment ? y : acc
  );
  const pessMin = pessTroughEntry.endingEndowment;
  const pessTroughYr = pessTroughEntry.fiscalYear;
  const firstBelowFloor = pessProj.years.find((y) => y.endingEndowment < boardFloor)?.fiscalYear;

  const rec = computeBriefRecommendation({
    pessFY35,
    pessMin,
    pessTroughYr,
    boardFloor,
    probAlways: mc.probAlwaysAboveFloor,
    probInsolv: mc.probInsolvent,
    pessFirstBelow: firstBelowFloor,
  });

  // Trajectory chart: historical FY15-FY26 + 3 scenarios FY27-FY35.
  const chartData = useMemo(() => {
    const map = new Map<number, Record<string, number | null>>();
    HISTORICAL_ENDOWMENT.forEach(({ fiscalYear, endingEndowment }) => {
      map.set(fiscalYear, { Historical: endingEndowment });
    });
    scenarios.forEach((s) => {
      s.years.forEach((y) => {
        const row = map.get(y.fiscalYear) ?? {};
        row[s.scenario] = y.endingEndowment;
        map.set(y.fiscalYear, row);
      });
    });
    // Bridge FY26 → FY27: scenarios start from the last historical value.
    const lastHist = HISTORICAL_ENDOWMENT[HISTORICAL_ENDOWMENT.length - 1];
    const bridge = map.get(lastHist.fiscalYear) ?? {};
    bridge.Base = lastHist.endingEndowment;
    bridge.Optimistic = lastHist.endingEndowment;
    bridge.Pessimistic = lastHist.endingEndowment;
    map.set(lastHist.fiscalYear, bridge);
    return Array.from(map.entries())
      .sort(([a], [b]) => a - b)
      .map(([fiscalYear, vals]) => ({ fiscalYear, ...vals }));
  }, [scenarios]);

  // Compact assumption summary so Eric sees what's driving the projection.
  const fundraisingHeadline = inputs.fundraising[0] / 1_000_000;
  const baseReturn = inputs.marketReturn.Base[0];
  const awardSizeHeadline = inputs.awardSize[0];

  return (
    <div className="space-y-5">
      <RecommendedAction
        context="Recommended action for the Board"
        severity={rec.severity}
        headline={rec.headline}
        rationale={rec.rationale}
        actions={rec.actions}
      />

      {/* Two side-by-side stat cards: financial outlook + mission impact.
          In print, these merge with the next two (liquidity + spending) into a
          single 4-column row so the whole Brief fits on one page. */}
      <div className="grid grid-cols-1 md:grid-cols-2 print:grid-cols-4 gap-4 print:gap-2 print-stat-grid">
        <BriefCard label="FY35 endowment outlook" subtitle="Where do we end up?">
          <div className="space-y-1.5 num">
            <BriefRow
              color={SCENARIO_COLORS.Base}
              label="Base"
              value={millions(baseProj.years[8].endingEndowment)}
              icon="●"
              bandClass={baseProj.years[8].endingEndowment >= boardFloor ? 'text-emerald-700' : 'text-rose-700'}
            />
            <BriefRow
              color={SCENARIO_COLORS.Optimistic}
              label="Optimistic"
              value={millions(optProj.years[8].endingEndowment)}
              icon="●"
              bandClass="text-emerald-700"
            />
            <BriefRow
              color={SCENARIO_COLORS.Pessimistic}
              label="Pessimistic"
              value={millions(pessProj.years[8].endingEndowment)}
              icon={pessProj.years[8].endingEndowment >= boardFloor ? '▲' : '✕'}
              bandClass={
                pessProj.years[8].endingEndowment >= boardFloor
                  ? 'text-amber-700'
                  : 'text-rose-700'
              }
            />
            <BriefRow
              color="#101A4C80"
              label="Bad-luck case (1-in-10 downside)"
              value={millions(mc.bands[8].p10)}
              icon={mc.bands[8].p10 >= boardFloor ? '▲' : '✕'}
              bandClass={mc.bands[8].p10 >= boardFloor ? 'text-amber-700' : 'text-rose-700'}
            />
          </div>
          <div className="mt-2 text-[11px] text-navy/60 font-sub space-y-1">
            <div>
              <strong className="text-navy">Floor reference:</strong> {millions(boardFloor)}{' '}
              <span className="italic">(board-considered policy minimum — confirm in Finance Cmte)</span>.
            </div>
            <div>
              In stress simulations, the endowment stays above {millions(boardFloor)} every year in{' '}
              <strong className="text-navy">{percent(mc.probAlwaysAboveFloor, 0)}</strong> of trials.
            </div>
            <div className="italic">
              Pessimistic ≈ a 2008-style two-year drawdown. Optimistic ≈ sustained outperformance.
              Bad-luck case = 10th-percentile of 1,000 stochastic simulations.
            </div>
          </div>
        </BriefCard>

        <BriefCard label="Mission impact (FY27–FY35)" subtitle="How many scholars do we serve?">
          <p className="text-sm text-navy/90 mb-2 leading-snug">
            We serve an average of{' '}
            <strong className="text-navy">{baseBridge.averageAnnualServed.toLocaleString()}</strong>{' '}
            scholars per year, hitting goal in{' '}
            <strong className="text-navy">
              {baseBridge.yearsAtOrAboveGoal} of {baseProj.years.length}
            </strong>{' '}
            years.
          </p>
          <div className="space-y-1.5">
            <BriefRow
              color="#101A4C"
              label="Average per year (Base)"
              value={baseBridge.averageAnnualServed.toLocaleString()}
              icon="●"
              bandClass="text-navy"
            />
            <BriefRow
              color="#101A4C"
              label="Cumulative scholars served"
              value={baseBridge.cumulativeServed.toLocaleString()}
              icon="●"
              bandClass="text-navy"
            />
            <BriefRow
              color="#101A4C"
              label="FY32 served vs. goal"
              value={`${baseBridge.fy32Served.toLocaleString()} / ${goalFY32.toLocaleString()}`}
              icon={baseFY32Pct >= 1 ? '●' : baseFY32Pct >= 0.85 ? '▲' : '✕'}
              bandClass={
                baseFY32Pct >= 1
                  ? 'text-emerald-700'
                  : baseFY32Pct >= 0.85
                    ? 'text-amber-700'
                    : 'text-rose-700'
              }
            />
            <BriefRow
              color="#101A4C"
              label="Years at/above goal"
              value={`${baseBridge.yearsAtOrAboveGoal} / ${baseProj.years.length}`}
              icon={baseBridge.yearsAtOrAboveGoal === 9 ? '●' : '▲'}
              bandClass={
                baseBridge.yearsAtOrAboveGoal === 9
                  ? 'text-emerald-700'
                  : 'text-amber-700'
              }
            />
          </div>
          <div className="mt-2 text-[11px] text-navy/60 font-sub">
            Avg award per scholar: ${awardSizeHeadline.toLocaleString()}.
          </div>
        </BriefCard>
      </div>

      {/* Endowment trajectory — single big chart. The "where have we been,
          where are we going" picture that does most of the talking. In print,
          this becomes the natural page-2 lead so the recommendation + key
          numbers fit on page 1. */}
      <section className="card print-page-break">
        <div className="card-header flex items-center justify-between flex-wrap gap-3">
          <div>
            <div className="eyebrow">Endowment trajectory</div>
            <h2 className="font-head text-base">
              FY15 historical · FY27–FY35 projection
              {viewMode === 'real' && (
                <span className="ml-2 text-xs font-sub font-normal text-purple normal-case tracking-normal">
                  · displayed in real (FY27 $) terms
                </span>
              )}
            </h2>
          </div>
        </div>
        <div className="card-body">
          <div className="h-[300px] print:h-[150px]">
            <ResponsiveContainer width="100%" height="100%">
              <LineChart data={chartData} margin={{ top: 10, right: 24, bottom: 8, left: 0 }}>
                <CartesianGrid strokeDasharray="2 4" stroke="#101A4C20" />
                <XAxis
                  dataKey="fiscalYear"
                  tick={{ fill: '#101A4C', fontSize: 12 }}
                  tickFormatter={(fy) => fyLabel(Number(fy))}
                  stroke="#101A4C40"
                />
                <YAxis
                  tick={{ fill: '#101A4C', fontSize: 12 }}
                  tickFormatter={(v) => `$${(v / 1_000_000).toFixed(0)}M`}
                  stroke="#101A4C40"
                  width={64}
                />
                <Tooltip
                  contentStyle={{
                    background: 'white',
                    border: '1px solid #101A4C20',
                    borderRadius: 8,
                    fontFamily: 'Noto Serif, serif',
                  }}
                  formatter={(v) => millions(Number(v))}
                  labelFormatter={(fy) => `FY${String(fy).slice(-2)}`}
                />
                <Line
                  type="monotone"
                  dataKey="Historical"
                  stroke={SCENARIO_COLORS.Historical}
                  strokeWidth={2.5}
                  dot={false}
                  connectNulls={false}
                />
                <Line
                  type="monotone"
                  dataKey="Base"
                  stroke={SCENARIO_COLORS.Base}
                  strokeWidth={2.5}
                  dot={{ r: 3 }}
                  connectNulls={false}
                />
                <Line
                  type="monotone"
                  dataKey="Optimistic"
                  stroke={SCENARIO_COLORS.Optimistic}
                  strokeWidth={2.5}
                  dot={{ r: 3 }}
                  connectNulls={false}
                />
                <Line
                  type="monotone"
                  dataKey="Pessimistic"
                  stroke={SCENARIO_COLORS.Pessimistic}
                  strokeWidth={2.5}
                  strokeDasharray="6 4"
                  dot={{ r: 3 }}
                  connectNulls={false}
                />
              </LineChart>
            </ResponsiveContainer>
          </div>
          <div className="flex items-center gap-4 text-xs mt-2 font-sub flex-wrap">
            {(['Historical', 'Base', 'Optimistic', 'Pessimistic'] as const).map((k) => (
              <span key={k} className="flex items-center gap-1.5">
                <span
                  className="inline-block w-3 h-0.5"
                  style={{
                    background: SCENARIO_COLORS[k],
                    borderTop: k === 'Pessimistic' ? `2px dashed ${SCENARIO_COLORS[k]}` : undefined,
                    height: k === 'Pessimistic' ? 0 : undefined,
                  }}
                />
                {k}
              </span>
            ))}
          </div>
        </div>
      </section>

      {/* Two more side-by-side: liquidity flag + spending discipline.
          Both single-line readouts with band coloring. */}
      <div className="grid grid-cols-1 md:grid-cols-2 print:grid-cols-2 gap-4 print:gap-2 print-stat-grid-2">
        <BriefCard
          label="Liquidity (FY35 Pessimistic)"
          subtitle="Could we pay our bills under stress?"
        >
          <div className="space-y-1.5">
            <BriefRow
              color="#101A4C"
              label="Operating reserve only"
              value={`${pessFY35Liq.reserveOnlyMonths.toFixed(1)} months`}
              icon={
                liquidityBand(pessFY35Liq.reserveOnlyMonths) === 'red'
                  ? '✕'
                  : liquidityBand(pessFY35Liq.reserveOnlyMonths) === 'amber'
                    ? '▲'
                    : '●'
              }
              bandClass={
                liquidityBand(pessFY35Liq.reserveOnlyMonths) === 'red'
                  ? 'text-rose-700'
                  : liquidityBand(pessFY35Liq.reserveOnlyMonths) === 'amber'
                    ? 'text-amber-700'
                    : 'text-emerald-700'
              }
            />
            <BriefRow
              color="#101A4C"
              label="Including quasi-endowment we could redesignate"
              value={`${pessFY35Liq.totalLiquidMonths.toFixed(1)} months`}
              icon={
                liquidityBand(pessFY35Liq.totalLiquidMonths) === 'red'
                  ? '✕'
                  : liquidityBand(pessFY35Liq.totalLiquidMonths) === 'amber'
                    ? '▲'
                    : '●'
              }
              bandClass={
                liquidityBand(pessFY35Liq.totalLiquidMonths) === 'red'
                  ? 'text-rose-700'
                  : liquidityBand(pessFY35Liq.totalLiquidMonths) === 'amber'
                    ? 'text-amber-700'
                    : 'text-emerald-700'
              }
            />
          </div>
          <div className="mt-2 text-[11px] text-navy/60 font-sub">
            Bands: ≥6 mo healthy · 3–6 mo watch · below 3 mo is the auditor going-concern threshold.
          </div>
        </BriefCard>

        <BriefCard label="Spending discipline (Base avg)" subtitle="Are we sustainable?">
          <p className="text-sm text-navy/90 mb-2 leading-snug">
            Average net draw of{' '}
            <strong className={
              avgSpendBase > 0.06
                ? 'text-rose-700'
                : avgSpendBase > SUSTAINABLE_SPEND_RATE
                  ? 'text-amber-700'
                  : 'text-emerald-700'
            }>{percent(avgSpendBase, 2)}</strong>
            {' '}vs. the {percent(SUSTAINABLE_SPEND_RATE, 1)} sustainable ceiling
            {avgSpendBase <= SUSTAINABLE_SPEND_RATE
              ? ' — we are under it.'
              : avgSpendBase <= 0.06
                ? ' — slightly above it (watch).'
                : ' — well over (action required).'}
          </p>
          <div className="space-y-1.5">
            {(() => {
              const avgProg =
                baseProj.years.reduce((acc, y) => acc + y.programRatio, 0) /
                baseProj.years.length;
              return (
                <BriefRow
                  color="#101A4C"
                  label="Program ratio (avg, dollars reaching mission)"
                  value={percent(avgProg, 1)}
                  icon={avgProg >= PROGRAM_RATIO_FLOOR ? '●' : '✕'}
                  bandClass={avgProg >= PROGRAM_RATIO_FLOOR ? 'text-emerald-700' : 'text-rose-700'}
                />
              );
            })()}
          </div>
          <div className="mt-2 text-[11px] text-navy/60 font-sub">
            Spend rate = (expenses − fundraising) ÷ beginning endowment. {percent(SUSTAINABLE_SPEND_RATE, 1)} is the standard endowment-policy ceiling. Program ratio ≥65% is the Charity Navigator floor.
          </div>
        </BriefCard>
      </div>

      {/* Compact assumption summary with a quick-edit affordance — keeps Eric
          from chasing assumptions, makes the projection's drivers visible. */}
      <section className="card border border-navy/10 bg-tan/40">
        <div className="card-body flex items-center justify-between flex-wrap gap-2 text-xs font-sub text-navy/80">
          <div>
            <strong className="text-navy">Assumptions driving this view:</strong>{' '}
            ${fundraisingHeadline.toFixed(1)}M/yr fundraising · {baseReturn}% Base return · ${awardSizeHeadline.toLocaleString()} avg award · {millions(boardFloor)} floor
          </div>
          {onEditAssumptions && (
            <button
              onClick={onEditAssumptions}
              className="no-print text-purple font-semibold underline underline-offset-2 hover:text-navy transition-colors"
            >
              Adjust assumptions →
            </button>
          )}
        </div>
      </section>
    </div>
  );
}

function BriefCard({
  label,
  subtitle,
  children,
}: {
  label: string;
  subtitle?: string;
  children: ReactNode;
}) {
  return (
    <section className="card">
      <div className="card-header">
        <div className="eyebrow">{label}</div>
        {subtitle && (
          <h2 className="font-head text-base">{subtitle}</h2>
        )}
      </div>
      <div className="card-body">{children}</div>
    </section>
  );
}

function BriefRow({
  color: _color,
  label,
  value,
  icon,
  bandClass,
}: {
  color: string;
  label: string;
  value: string;
  icon: string;
  bandClass: string;
}) {
  void _color; // reserved for future per-row swatch
  return (
    <div className="flex items-baseline justify-between gap-3 border-b border-navy/5 pb-1 last:border-b-0">
      <span className="text-navy/80 text-sm">{label}</span>
      <span className={`font-semibold num text-sm ${bandClass}`}>
        <span aria-hidden="true" className="mr-1">
          {icon}
        </span>
        {value}
      </span>
    </div>
  );
}

function computeBriefRecommendation(args: {
  pessFY35: number;
  pessMin: number;
  pessTroughYr?: number;
  boardFloor: number;
  probAlways: number;
  probInsolv: number;
  pessFirstBelow?: number;
}): {
  severity: ActionSeverity;
  headline: string;
  rationale: ReactNode;
  actions: ReactNode[];
} {
  const { pessFY35, pessMin, pessTroughYr, boardFloor, probAlways, probInsolv, pessFirstBelow } = args;

  if (probInsolv >= 0.05 || pessMin < 0) {
    return {
      severity: 'urgent',
      headline: 'Action required — pessimistic case shows tail risk above the threshold',
      rationale: (
        <>
          Under Pessimistic, the endowment falls to <strong>{millions(pessMin)}</strong> at its
          lowest point{pessTroughYr ? ` in FY${String(pessTroughYr).slice(-2)}` : ''}. In stress
          simulations, <strong>{percent(probInsolv, 1)}</strong> of paths reach insolvency, and
          only <strong>{percent(probAlways, 0)}</strong> stay above {millions(boardFloor)} every
          year.
        </>
      ),
      actions: [
        'Convene the Finance + Investment Committees this quarter to review the spending policy and the policy floor.',
        'Decide in advance the trigger that would let us shift quasi-endowment into operating reserve, before we need it.',
        'Test a fundraising surge — could a major-gifts campaign close the implied gap?',
      ],
    };
  }

  if (pessFirstBelow !== undefined || probAlways < 0.85) {
    return {
      severity: 'watch',
      headline: 'Watch — pessimistic case dips below the floor before recovering',
      rationale: (
        <>
          Pessimistic FY35 ends at <strong>{millions(pessFY35)}</strong>, but the path dips below{' '}
          {millions(boardFloor)} mid-window
          {pessFirstBelow ? ` (first breach in FY${String(pessFirstBelow).slice(-2)}` : ''}
          {pessTroughYr ? `; trough in FY${String(pessTroughYr).slice(-2)} at ${millions(pessMin)})` : pessFirstBelow ? ')' : ''}.
          In stress simulations, the endowment stays above the floor every year in{' '}
          <strong>{percent(probAlways, 0)}</strong> of trials. Recoverable; worth a Finance Committee
          briefing.
        </>
      ),
      actions: [
        'Brief the Finance Committee at the next meeting.',
        'Confirm fundraising and award assumptions are realistic against actuals.',
        'Consider lowering the spending policy by 0.5 percentage points (e.g., 4.5% → 4.0%) to avoid the breach.',
      ],
    };
  }

  return {
    severity: 'on-track',
    headline: `On track — even in Pessimistic the endowment stays above ${millions(boardFloor)}`,
    rationale: (
      <>
        Pessimistic FY35 ends at <strong>{millions(pessFY35)}</strong>, with a trough of{' '}
        <strong>{millions(pessMin)}</strong>
        {pessTroughYr ? ` in FY${String(pessTroughYr).slice(-2)}` : ''}. In stress simulations, the
        endowment stays above the floor every year in <strong>{percent(probAlways, 0)}</strong> of
        trials. The current plan is defensible at the Finance Committee level under reasonable stress.
      </>
    ),
    actions: [
      'Annual review at the Finance Committee.',
      'Maintain quarterly tracking against Pessimistic to confirm reality is not bending downward.',
    ],
  };
}
