/**
 * RecommendedAction — contextual board-action panel surfaced on every tab.
 *
 * Goal: turn data into a decision. Each call site passes a `severity` (the
 * traffic-light read on what the data shows) and a `headline` + `rationale` +
 * optional `actions` list. The component handles the visual chrome consistent
 * with brand patterns and makes the panel print-ready (it's the punchline a
 * board member should remember).
 */
import type { ReactNode } from 'react';

export type ActionSeverity = 'on-track' | 'watch' | 'urgent';

interface Props {
  severity: ActionSeverity;
  headline: string;
  rationale: ReactNode;
  /** Optional bullet list of recommended actions. */
  actions?: ReactNode[];
  /** Tab/context label shown on the eyebrow. */
  context?: string;
}

const STYLES: Record<
  ActionSeverity,
  { ring: string; bg: string; pillBg: string; text: string; icon: string; label: string }
> = {
  'on-track': {
    ring: 'border-emerald-300',
    bg: 'bg-emerald-50/60',
    pillBg: 'bg-emerald-100 text-emerald-800',
    text: 'text-emerald-900',
    icon: '●',
    label: 'On track',
  },
  watch: {
    ring: 'border-amber-300',
    bg: 'bg-amber-50/60',
    pillBg: 'bg-amber-100 text-amber-800',
    text: 'text-amber-900',
    icon: '▲',
    label: 'Watch',
  },
  urgent: {
    ring: 'border-rose-400',
    bg: 'bg-rose-50/60',
    pillBg: 'bg-rose-100 text-rose-800',
    text: 'text-rose-900',
    icon: '✕',
    label: 'Action required',
  },
};

export function RecommendedAction({
  severity,
  headline,
  rationale,
  actions,
  context,
}: Props) {
  const s = STYLES[severity];
  return (
    <section className={`card border-2 ${s.ring} ${s.bg}`}>
      <div className="card-header flex items-center justify-between flex-wrap gap-3">
        <div>
          <div className="eyebrow">{context ?? 'Recommended action'}</div>
          <h2 className={`font-head text-base ${s.text}`}>{headline}</h2>
        </div>
        <span
          className={`pill gap-1 ${s.pillBg}`}
          aria-label={`Status: ${s.label}`}
        >
          <span aria-hidden="true">{s.icon}</span>
          {s.label}
        </span>
      </div>
      <div className="card-body text-sm font-sub space-y-2">
        <div className="text-navy/80">{rationale}</div>
        {actions && actions.length > 0 && (
          <div>
            <div className="eyebrow mb-1">Suggested next steps</div>
            <ul className="list-disc list-inside space-y-0.5 text-navy/80">
              {actions.map((a, i) => (
                <li key={i}>{a}</li>
              ))}
            </ul>
          </div>
        )}
      </div>
    </section>
  );
}
