/** Brand-consistent formatting helpers used across the app. */

const EM_DASH = '—';

/** Returns true when n is null/undefined/NaN/±Infinity — i.e. anything that
 *  would render "$NaNM" or "$InfinityM" if we let it flow through. */
function isUnrenderable(n: unknown): boolean {
  return n === null || n === undefined || typeof n !== 'number' || !Number.isFinite(n);
}

export function dollars(n: number, opts?: { compact?: boolean }): string {
  if (isUnrenderable(n)) return EM_DASH;
  if (opts?.compact) {
    if (Math.abs(n) >= 1_000_000) {
      return `$${(n / 1_000_000).toFixed(n >= 10_000_000 ? 0 : 1)}M`;
    }
    if (Math.abs(n) >= 1_000) {
      return `$${(n / 1_000).toFixed(0)}K`;
    }
  }
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD',
    maximumFractionDigits: 0,
  }).format(n);
}

export function millions(n: number, fractionDigits = 1): string {
  if (isUnrenderable(n)) return EM_DASH;
  const m = n / 1_000_000;
  const sign = m < 0 ? '-' : '';
  return `${sign}$${Math.abs(m).toFixed(fractionDigits)}M`;
}

export function percent(n: number, fractionDigits = 1): string {
  if (isUnrenderable(n)) return EM_DASH;
  return `${(n * 100).toFixed(fractionDigits)}%`;
}

export function fyLabel(fy: number): string {
  return `FY${String(fy).slice(-2)}`;
}
