import { useMemo, useState } from 'react';
import {
  Bar,
  BarChart,
  CartesianGrid,
  Cell,
  LabelList,
  ReferenceLine,
  ResponsiveContainer,
  Tooltip,
  XAxis,
  YAxis,
} from 'recharts';
import type { FinancialInputs, ScenarioProjection } from '../../lib/model';
import { SUSTAINABLE_SPEND_RATE, projectScenario } from '../../lib/model';
import { millions } from '../../lib/format';
import { NAVY, PURPLE } from '../../lib/colors';

interface Props {
  inputs: FinancialInputs;
}

interface Driver {
  key: string;
  label: string;
  description: string;
  perturb: (inp: FinancialInputs, deltaPct: number) => FinancialInputs;
}

const DRIVERS: Driver[] = [
  {
    key: 'fundraising',
    label: 'Fundraising',
    description: 'Per-year fundraising target × (1 ± Δ)',
    perturb: (inp, d) => ({
      ...inp,
      fundraising: inp.fundraising.map((v) => v * (1 + d / 100)),
    }),
  },
  {
    key: 'marketReturn',
    label: 'Market return (Base)',
    description: 'Annual base-scenario return + Δ percentage points',
    perturb: (inp, d) => ({
      ...inp,
      marketReturn: {
        ...inp.marketReturn,
        Base: inp.marketReturn.Base.map((v) => v + d * 0.1),
        // Note: ±10% delta translates to ±1pp on return — preserves comparability across drivers.
      },
    }),
  },
  {
    key: 'opGrowth',
    label: 'Op-expense growth',
    description: 'Annual operating-expense growth rate × (1 ± Δ)',
    perturb: (inp, d) => ({
      ...inp,
      opExpensesGrowth: inp.opExpensesGrowth * (1 + d / 100),
    }),
  },
  {
    key: 'awardCosts',
    label: 'Award costs',
    description: 'Per-year award costs × (1 ± Δ)',
    perturb: (inp, d) => ({
      ...inp,
      awardCosts: inp.awardCosts.map((v) => v * (1 + d / 100)),
    }),
  },
  {
    key: 'beginningEndowment',
    label: 'Beginning endowment',
    description: 'FY27 starting endowment × (1 ± Δ)',
    perturb: (inp, d) => ({
      ...inp,
      beginningEndowment: inp.beginningEndowment * (1 + d / 100),
    }),
  },
  {
    key: 'opInit',
    label: 'Op-expense init',
    description: 'FY27 operating-expense baseline × (1 ± Δ)',
    perturb: (inp, d) => ({
      ...inp,
      opExpensesInit: inp.opExpensesInit * (1 + d / 100),
    }),
  },
];

type MetricKey = 'fy35Ending' | 'minEndowment' | 'avgSpendRate' | 'yearsAboveSustainable';

interface MetricDef {
  key: MetricKey;
  label: string;
  shortLabel: string;
  unit: 'dollars' | 'percent' | 'years';
  /** Direction in which positive change = favorable for the org. Used to color the legend. */
  favorableDirection: 'up' | 'down';
  description: string;
  compute: (proj: ScenarioProjection) => number;
}

const METRICS: MetricDef[] = [
  {
    key: 'fy35Ending',
    label: 'FY35 ending endowment',
    shortLabel: 'FY35 endowment',
    unit: 'dollars',
    favorableDirection: 'up',
    description: 'Endowment balance at the close of FY35. Higher is better.',
    compute: (p) => p.years[p.years.length - 1].endingEndowment,
  },
  {
    key: 'minEndowment',
    label: 'Minimum endowment across FY27–FY35',
    shortLabel: 'Min endowment',
    unit: 'dollars',
    favorableDirection: 'up',
    description: 'Lowest year-end endowment value over the projection. Captures worst-point depth.',
    compute: (p) => Math.min(...p.years.map((y) => y.endingEndowment)),
  },
  {
    key: 'avgSpendRate',
    label: 'Average net spend rate (FY27–FY35)',
    shortLabel: 'Avg spend rate',
    unit: 'percent',
    favorableDirection: 'down',
    description:
      'Mean of the per-year net spend rate (totalExpenses − fundraising) ÷ beginning endowment. Lower is better; 4.5% is the sustainable benchmark.',
    compute: (p) =>
      p.years.reduce((acc, y) => acc + y.spendRate, 0) / p.years.length,
  },
  {
    key: 'yearsAboveSustainable',
    label: 'Years above 4.5% sustainable spend',
    shortLabel: 'Years > 4.5%',
    unit: 'years',
    favorableDirection: 'down',
    description:
      'Count of fiscal years where net spend rate exceeds the 4.5% sustainable benchmark. Lower is better; 0 = fully sustainable.',
    compute: (p) =>
      p.years.filter((y) => y.spendRate > SUSTAINABLE_SPEND_RATE).length,
  },
];

function formatMetric(value: number, unit: MetricDef['unit']): string {
  if (unit === 'dollars') return millions(value, 1);
  if (unit === 'percent') return `${(value * 100).toFixed(2)}%`;
  return value.toFixed(1);
}

function formatMetricDelta(value: number, unit: MetricDef['unit']): string {
  const sign = value >= 0 ? '+' : '';
  if (unit === 'dollars') return `${sign}${millions(value, 1)}`;
  if (unit === 'percent') return `${sign}${(value * 100).toFixed(2)}pp`;
  return `${sign}${value.toFixed(1)}`;
}

/** Like formatMetricDelta but always emits an absolute value (no sign).
 *  Used for the "Range = |+| + |−|" column where the value is by definition non-negative. */
function formatMetricRange(value: number, unit: MetricDef['unit']): string {
  const v = Math.abs(value);
  if (unit === 'dollars') return millions(v, 1);
  if (unit === 'percent') return `${(v * 100).toFixed(2)}pp`;
  return v.toFixed(1);
}

export function SensitivityTornado({ inputs }: Props) {
  const [delta, setDelta] = useState<number>(10);
  const [metricKey, setMetricKey] = useState<MetricKey>('fy35Ending');

  const metric = METRICS.find((m) => m.key === metricKey)!;

  const baseline = useMemo(() => {
    const proj = projectScenario(inputs, 'Base');
    return metric.compute(proj);
  }, [inputs, metric]);

  const data = useMemo(() => {
    return DRIVERS.map((d) => {
      const high = projectScenario(d.perturb(inputs, +delta), 'Base');
      const low = projectScenario(d.perturb(inputs, -delta), 'Base');
      const highVal = metric.compute(high);
      const lowVal = metric.compute(low);
      const upside = highVal - baseline;
      const downside = lowVal - baseline;
      const range = Math.abs(upside) + Math.abs(downside);
      return {
        key: d.key,
        label: d.label,
        description: d.description,
        upside,
        downside,
        range,
      };
    }).sort((a, b) => b.range - a.range);
  }, [inputs, delta, baseline, metric]);

  // Recharts horizontal bar: use stacked bars centered on zero by giving negative + positive values.
  const chartData = data.map((d) => ({
    label: d.label,
    upside: d.upside,
    downside: d.downside,
  }));

  // Color logic: NAVY = favorable change, PURPLE = unfavorable change.
  // For "up is favorable" metrics, +Δ-driven upside is favorable when upside > 0.
  // For "down is favorable" metrics (spend rate, years > sustainable), +Δ-driven upside is favorable when upside < 0.
  const isFavorable = (val: number): boolean =>
    metric.favorableDirection === 'up' ? val > 0 : val < 0;

  const xTickFormatter = (v: number) => {
    if (metric.unit === 'dollars') return millions(v, 0);
    if (metric.unit === 'percent') return `${(v * 100).toFixed(1)}pp`;
    return v.toFixed(1);
  };

  return (
    <div className="space-y-6">
      <section className="card">
        <div className="card-header flex items-center justify-between flex-wrap gap-3">
          <div>
            <div className="eyebrow">Sensitivity tornado</div>
            <h2 className="font-head text-base">
              {metric.label} — drivers ranked by impact
            </h2>
          </div>
          <div className="flex items-center gap-4 text-sm flex-wrap">
            <div className="flex items-center gap-2">
              <label className="text-navy/70 font-semibold">Output metric:</label>
              <select
                className="input-num min-w-[14rem]"
                value={metricKey}
                onChange={(e) => setMetricKey(e.target.value as MetricKey)}
              >
                {METRICS.map((m) => (
                  <option key={m.key} value={m.key}>
                    {m.shortLabel}
                  </option>
                ))}
              </select>
            </div>
            <div className="flex items-center gap-2">
              <label className="text-navy/70 font-semibold">Perturbation (±%):</label>
              <input
                type="number"
                step="1"
                min="1"
                max="50"
                className="input-num w-20"
                value={delta}
                onChange={(e) => setDelta(Math.max(1, Number(e.target.value)))}
              />
            </div>
          </div>
        </div>
        <div className="card-body">
          <p className="text-xs text-navy/60 font-sub mb-2">
            Baseline {metric.shortLabel.toLowerCase()}:{' '}
            <strong className="text-navy num">{formatMetric(baseline, metric.unit)}</strong>.
            Each driver is independently perturbed by ±{delta}%
            (market return uses ±{(delta / 10).toFixed(1)}pp). Bar length = absolute change in {metric.shortLabel.toLowerCase()}.
            For this metric, <strong>{metric.favorableDirection === 'up' ? 'higher' : 'lower'} is better</strong>.
          </p>
          <div className="h-[360px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart
                data={chartData}
                layout="vertical"
                margin={{ top: 10, right: 36, bottom: 8, left: 16 }}
                /* Removed stackOffset="sign" + stackId so each Bar anchors
                   independently at zero. With stack, same-sign perturbations
                   (rare but possible for non-monotonic drivers) silently
                   overlapped into a single visual segment. Independent bars
                   may overlap visually in same-sign cases, but the LabelList
                   on each side disambiguates. */
              >
                <CartesianGrid strokeDasharray="2 4" stroke="#101A4C15" horizontal={false} />
                <XAxis
                  type="number"
                  tick={{ fill: '#101A4C', fontSize: 12 }}
                  tickFormatter={xTickFormatter}
                  stroke="#101A4C40"
                />
                <YAxis
                  type="category"
                  dataKey="label"
                  tick={{ fill: '#101A4C', fontSize: 12, fontWeight: 600 }}
                  stroke="#101A4C40"
                  width={180}
                />
                <Tooltip
                  contentStyle={{
                    background: 'white',
                    border: '1px solid #101A4C20',
                    borderRadius: 8,
                    fontFamily: 'Noto Serif, serif',
                  }}
                  formatter={(v: number) => formatMetricDelta(v, metric.unit)}
                />
                <ReferenceLine x={0} stroke="#101A4C" strokeWidth={1.5} />
                <Bar dataKey="downside" name={`-${delta}%`}>
                  {chartData.map((d, i) => (
                    <Cell key={i} fill={isFavorable(d.downside) ? NAVY : PURPLE} />
                  ))}
                  <LabelList
                    dataKey="downside"
                    position="left"
                    formatter={(v: number) => formatMetricDelta(v, metric.unit)}
                    fill="#101A4C"
                    fontSize={11}
                    fontWeight={600}
                  />
                </Bar>
                <Bar dataKey="upside" name={`+${delta}%`}>
                  {chartData.map((d, i) => (
                    <Cell key={i} fill={isFavorable(d.upside) ? NAVY : PURPLE} />
                  ))}
                  <LabelList
                    dataKey="upside"
                    position="right"
                    formatter={(v: number) => formatMetricDelta(v, metric.unit)}
                    fill="#101A4C"
                    fontSize={11}
                    fontWeight={600}
                  />
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
          <div className="flex items-center gap-4 text-xs mt-2 font-sub flex-wrap">
            <span className="flex items-center gap-2">
              <span className="inline-block w-3 h-3 rounded-sm" style={{ background: NAVY }} />
              Favorable move ({metric.favorableDirection === 'up' ? 'metric increases' : 'metric decreases'})
            </span>
            <span className="flex items-center gap-2">
              <span className="inline-block w-3 h-3 rounded-sm" style={{ background: PURPLE }} />
              Adverse move ({metric.favorableDirection === 'up' ? 'metric decreases' : 'metric increases'})
            </span>
          </div>
          <p className="text-xs text-navy/60 mt-3 font-sub italic">
            {metric.description}
          </p>
        </div>
      </section>

      <section className="card">
        <div className="card-header">
          <div className="eyebrow">Driver definitions</div>
          <h2 className="font-head text-base">What each lever moves</h2>
        </div>
        <div className="card-body">
          <table className="w-full text-sm">
            <thead>
              <tr className="text-navy/60 uppercase text-xs tracking-wider">
                <th className="text-left py-2 pr-4 font-semibold">Driver</th>
                <th className="text-left py-2 pr-4 font-semibold">Definition</th>
                <th className="text-right py-2 pr-4 font-semibold">
                  Range (|+| + |−|)
                </th>
              </tr>
            </thead>
            <tbody>
              {data.map((d) => (
                <tr key={d.key} className="border-b border-navy/5">
                  <td className="text-left py-2 pr-4 font-semibold text-navy">{d.label}</td>
                  <td className="text-left py-2 pr-4 text-navy/80 font-sub">{d.description}</td>
                  <td className="text-right py-2 pr-4 font-semibold num">
                    {formatMetricRange(d.range, metric.unit)}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </section>
    </div>
  );
}
