import { useMemo, useState } from 'react';
import type {
  FinancialInputs,
  GoalSeekMetric,
  GoalSeekVariable,
  ScenarioName,
} from '../../lib/model';
import { goalSeek } from '../../lib/model';
import { dollars, millions, percent } from '../../lib/format';

interface Props {
  inputs: FinancialInputs;
}

interface VariableDef {
  key: GoalSeekVariable;
  label: string;
  description: string;
  unit: 'dollars' | 'percent' | 'count';
  defaultLo: number;
  defaultHi: number;
}

const VARIABLES: VariableDef[] = [
  {
    key: 'fundraisingFlat',
    label: 'Annual fundraising target (flat across years)',
    description:
      'Single fundraising number applied to every year of the projection. Solves for the level required to hit the target metric.',
    unit: 'dollars',
    defaultLo: 0,
    defaultHi: 30_000_000,
  },
  {
    key: 'marketReturnFlat',
    label: 'Base-scenario market return (flat)',
    description:
      'Single annual return applied to Base across the window. Optimistic gets +1.5pp; Pessimistic stays at the configured stress.',
    unit: 'percent',
    defaultLo: 0,
    defaultHi: 12,
  },
  {
    key: 'awardSizeFlat',
    label: 'Average award size (flat across years)',
    description:
      'Single per-scholar award amount applied every year. Higher award size → fewer scholars served at fixed total.',
    unit: 'dollars',
    defaultLo: 1_000,
    defaultHi: 20_000,
  },
  {
    key: 'beginningEndowment',
    label: 'FY27 beginning endowment',
    description:
      'Starting endowment value at the projection start. Solves for what corpus is needed to support the target.',
    unit: 'dollars',
    defaultLo: 50_000_000,
    defaultHi: 200_000_000,
  },
];

interface MetricDef {
  key: GoalSeekMetric;
  label: string;
  description: string;
  unit: 'dollars' | 'count';
  defaultTarget: number;
}

const METRICS: MetricDef[] = [
  {
    key: 'fy32Scholars',
    label: 'FY32 scholars served',
    description: 'Per Preston (2026-04-28) — strategic plan goal: 550 by FY32.',
    unit: 'count',
    defaultTarget: 550,
  },
  {
    key: 'fy35Scholars',
    label: 'FY35 scholars served',
    description: 'Steady-state scholars served at the end of the projection window.',
    unit: 'count',
    defaultTarget: 550,
  },
  {
    key: 'cumulativeScholars',
    label: 'Cumulative scholars FY27–FY35',
    description: 'Total scholars served across the 9-year window. Aggregate program impact.',
    unit: 'count',
    defaultTarget: 5_500,
  },
  {
    key: 'fy35Ending',
    label: 'FY35 ending endowment',
    description: 'Endowment level at the close of FY35. Use for corpus-preservation targets.',
    unit: 'dollars',
    defaultTarget: 100_000_000,
  },
  {
    key: 'minEndowment',
    label: 'Minimum endowment across FY27–FY35',
    description: 'Worst-year endowment value. Use for floor-protection targets.',
    unit: 'dollars',
    defaultTarget: 60_000_000,
  },
];

function formatVariable(value: number, unit: VariableDef['unit']): string {
  if (unit === 'dollars') return dollars(value);
  if (unit === 'percent') return `${value.toFixed(2)}%`;
  return value.toFixed(0);
}

function formatMetric(value: number, unit: MetricDef['unit']): string {
  if (unit === 'dollars') return millions(value);
  return Math.round(value).toLocaleString();
}

export function GoalSeek({ inputs }: Props) {
  // Default: award size × FY32 scholars at 550 — directly answers Preston's
  // stated goal ("550 by FY32, $6K avg award"). The current $4.2M award costs
  // / 550 = $7,636 — bisection lands here.
  const [variable, setVariable] = useState<GoalSeekVariable>('awardSizeFlat');
  const [metric, setMetric] = useState<GoalSeekMetric>('fy32Scholars');
  const [target, setTarget] = useState<number>(550);
  const [scenario, setScenario] = useState<ScenarioName>('Base');
  const [lo, setLo] = useState<number>(1_000);
  const [hi, setHi] = useState<number>(20_000);

  const variableDef = VARIABLES.find((v) => v.key === variable)!;
  const metricDef = METRICS.find((m) => m.key === metric)!;

  // Reset bounds + target when variable/metric changes
  const handleVariableChange = (k: GoalSeekVariable) => {
    setVariable(k);
    const def = VARIABLES.find((v) => v.key === k)!;
    setLo(def.defaultLo);
    setHi(def.defaultHi);
  };
  const handleMetricChange = (k: GoalSeekMetric) => {
    setMetric(k);
    const def = METRICS.find((m) => m.key === k)!;
    setTarget(def.defaultTarget);
  };

  const result = useMemo(
    () =>
      goalSeek(inputs, {
        variable,
        lo,
        hi,
        metric,
        target,
        scenario,
      }),
    [inputs, variable, lo, hi, metric, target, scenario]
  );

  const statusBand =
    result.status === 'converged'
      ? 'pill-green'
      : result.status === 'maxIterations'
        ? 'pill-yellow'
        : 'pill-red';
  const statusLabel =
    result.status === 'converged'
      ? '● Converged'
      : result.status === 'maxIterations'
        ? '▲ Max iterations'
        : '✕ Out of range';

  const distanceFromTarget = Math.abs(result.achievedMetric - target);
  const pctOfTarget = target !== 0 ? result.achievedMetric / target : 0;

  return (
    <div className="space-y-6">
      <section className="card">
        <div className="card-header">
          <div className="eyebrow">Goal-seek</div>
          <h2 className="font-head text-base">
            Solve backwards: pick the target, find the variable
          </h2>
        </div>
        <div className="card-body grid grid-cols-1 md:grid-cols-2 gap-4">
          <div className="space-y-3">
            <div>
              <label className="eyebrow">Solve for variable</label>
              <select
                className="input-num w-full mt-1"
                value={variable}
                onChange={(e) => handleVariableChange(e.target.value as GoalSeekVariable)}
              >
                {VARIABLES.map((v) => (
                  <option key={v.key} value={v.key}>
                    {v.label}
                  </option>
                ))}
              </select>
              <p className="text-[11px] text-navy/70 font-sub mt-1">
                {variableDef.description}
              </p>
            </div>

            <div className="grid grid-cols-2 gap-2">
              <div>
                <label className="eyebrow">Search lower</label>
                <input
                  type="number"
                  className="input-num w-full mt-1"
                  value={variableDef.unit === 'dollars' ? lo / 1_000_000 : lo}
                  step={variableDef.unit === 'dollars' ? 0.5 : 0.5}
                  onChange={(e) =>
                    setLo(
                      variableDef.unit === 'dollars'
                        ? Number(e.target.value) * 1_000_000
                        : Number(e.target.value)
                    )
                  }
                />
                <span className="text-[11px] text-navy/60 font-sub">
                  {variableDef.unit === 'dollars' ? '$M' : variableDef.unit === 'percent' ? '%' : ''}
                </span>
              </div>
              <div>
                <label className="eyebrow">Search upper</label>
                <input
                  type="number"
                  className="input-num w-full mt-1"
                  value={variableDef.unit === 'dollars' ? hi / 1_000_000 : hi}
                  step={variableDef.unit === 'dollars' ? 0.5 : 0.5}
                  onChange={(e) =>
                    setHi(
                      variableDef.unit === 'dollars'
                        ? Number(e.target.value) * 1_000_000
                        : Number(e.target.value)
                    )
                  }
                />
                <span className="text-[11px] text-navy/60 font-sub">
                  {variableDef.unit === 'dollars' ? '$M' : variableDef.unit === 'percent' ? '%' : ''}
                </span>
              </div>
            </div>
          </div>

          <div className="space-y-3">
            <div>
              <label className="eyebrow">Target metric</label>
              <select
                className="input-num w-full mt-1"
                value={metric}
                onChange={(e) => handleMetricChange(e.target.value as GoalSeekMetric)}
              >
                {METRICS.map((m) => (
                  <option key={m.key} value={m.key}>
                    {m.label}
                  </option>
                ))}
              </select>
              <p className="text-[11px] text-navy/70 font-sub mt-1">
                {metricDef.description}
              </p>
            </div>

            <div className="grid grid-cols-2 gap-2">
              <div>
                <label className="eyebrow">Target value</label>
                <input
                  type="number"
                  className="input-num w-full mt-1"
                  value={metricDef.unit === 'dollars' ? target / 1_000_000 : target}
                  step={metricDef.unit === 'dollars' ? 0.5 : 1}
                  onChange={(e) =>
                    setTarget(
                      metricDef.unit === 'dollars'
                        ? Number(e.target.value) * 1_000_000
                        : Number(e.target.value)
                    )
                  }
                />
                <span className="text-[11px] text-navy/60 font-sub">
                  {metricDef.unit === 'dollars' ? '$M' : 'count'}
                </span>
              </div>
              <div>
                <label className="eyebrow">Scenario</label>
                <select
                  className="input-num w-full mt-1"
                  value={scenario}
                  onChange={(e) => setScenario(e.target.value as ScenarioName)}
                >
                  <option value="Base">Base</option>
                  <option value="Optimistic">Optimistic</option>
                  <option value="Pessimistic">Pessimistic</option>
                </select>
              </div>
            </div>
          </div>
        </div>
      </section>

      <section className="card">
        <div className="card-header flex items-center justify-between flex-wrap gap-3">
          <div>
            <div className="eyebrow">Result</div>
            <h2 className="font-head text-base">
              Required {variableDef.label.split(' ')[0].toLowerCase()} to hit target
            </h2>
          </div>
          <span className={`pill gap-1 ${statusBand}`}>{statusLabel}</span>
        </div>
        <div className="card-body grid grid-cols-1 md:grid-cols-3 gap-4">
          <ResultCard
            label="Required value"
            value={formatVariable(result.variableValue, variableDef.unit)}
            subtitle={variableDef.label}
            big
          />
          <ResultCard
            label="Achieved metric"
            value={formatMetric(result.achievedMetric, metricDef.unit)}
            subtitle={`Target: ${formatMetric(target, metricDef.unit)} · ${percent(pctOfTarget, 0)} of target`}
          />
          <ResultCard
            label="Convergence"
            value={`${result.iterations} iterations`}
            subtitle={
              result.status === 'converged'
                ? `Within ${formatMetric(distanceFromTarget, metricDef.unit)} of target`
                : result.status === 'noBracket'
                  ? 'Target outside search range — widen bounds'
                  : 'Hit max iterations — try widening bounds'
            }
          />
        </div>
        <div className="card-body border-t border-navy/10 text-xs text-navy/70 font-sub">
          <p>
            <strong className="text-navy">Method:</strong> monotonic bisection over the search range, holding all other inputs fixed. Single-variable solver — for joint optimization (multiple variables at once), pick the most binding lever.
          </p>
          <p className="mt-1">
            <strong className="text-navy">Limitation:</strong> probability-based metrics (P(insolvency)) are not yet supported because Monte Carlo sampling noise breaks bisection convergence. Use the Stress Test tab for those.
          </p>
        </div>
      </section>

      <section className="card">
        <div className="card-header">
          <div className="eyebrow">Suggested questions</div>
          <h2 className="font-head text-base">Common goal-seek questions for the Board</h2>
        </div>
        <div className="card-body text-sm">
          <ul className="list-disc list-inside space-y-1 font-sub">
            <li>
              What flat <strong>fundraising</strong> level keeps FY35 endowment ≥ $80M under <strong>Pessimistic</strong>?
            </li>
            <li>
              At what <strong>award size</strong> do we hit Preston's 550 FY32 scholar goal exactly (no overshoot)?
            </li>
            <li>
              What <strong>market return</strong> assumption is required to keep the minimum endowment ≥ $40M floor?
            </li>
            <li>
              How much larger does the <strong>beginning endowment</strong> need to be to fund 5,500 cumulative scholars at current cost trajectory?
            </li>
          </ul>
        </div>
      </section>
    </div>
  );
}

function ResultCard({
  label,
  value,
  subtitle,
  big,
}: {
  label: string;
  value: string;
  subtitle?: string;
  big?: boolean;
}) {
  return (
    <div className="rounded-lg border border-navy/15 bg-white px-4 py-3">
      <div className="eyebrow">{label}</div>
      <div className={`font-head num text-navy mt-1 ${big ? 'text-3xl' : 'text-xl'}`}>{value}</div>
      {subtitle && <div className="text-xs text-navy/70 font-sub mt-1">{subtitle}</div>}
    </div>
  );
}
