export type ViewMode = 'nominal' | 'real';

interface HeaderProps {
  asOf: string;
  /** When true, render a persistent purple mode pill in the header so the
   *  user always knows the projection is using Committed + haircut × Likely
   *  rather than the raw fundraising target. UX audit Tier 1 #3. */
  autoLinkOn?: boolean;
  /** Current display mode — nominal $ or real (FY27 $). Default 'nominal'. */
  viewMode: ViewMode;
  setViewMode: (m: ViewMode) => void;
}

export function Header({ asOf, autoLinkOn, viewMode, setViewMode }: HeaderProps) {
  return (
    <header className="bg-navy text-white">
      <div className="max-w-screen-2xl mx-auto px-6 py-5 flex items-center justify-between gap-6">
        <div className="flex items-center gap-4">
          <img
            src="dccap-logo-nav.png"
            alt="DC CAP Scholars"
            className="h-12 w-auto"
            style={{ filter: 'brightness(0) invert(1)' }}
          />
          <div className="border-l border-white/20 pl-4">
            <div className="eyebrow text-purple-300 !text-purple-100/90">DC CAP Innovation Hub</div>
            <h1 className="text-xl md:text-2xl font-head uppercase tracking-wide-15 leading-tight">
              Financial Scenarios
            </h1>
            <p className="text-xs text-white/70 font-sub mt-0.5">
              FY27 baseline · FY27 – FY35 projection · As of {asOf}
            </p>
          </div>
        </div>
        <div className="hidden md:flex items-center gap-3 text-right">
          {/* Nominal / Real toggle. Real = FY27 dollars (deflated by user CPI). */}
          <div
            role="group"
            aria-label="Display mode"
            className="inline-flex items-center bg-white/10 rounded-full border border-white/20 overflow-hidden"
          >
            <button
              onClick={() => setViewMode('nominal')}
              className={`px-3 py-1 text-xs font-semibold uppercase tracking-wider transition-colors ${
                viewMode === 'nominal' ? 'bg-purple text-white' : 'text-white/70 hover:text-white'
              }`}
              aria-pressed={viewMode === 'nominal'}
            >
              Nominal $
            </button>
            <button
              onClick={() => setViewMode('real')}
              className={`px-3 py-1 text-xs font-semibold uppercase tracking-wider transition-colors ${
                viewMode === 'real' ? 'bg-purple text-white' : 'text-white/70 hover:text-white'
              }`}
              aria-pressed={viewMode === 'real'}
              title="Real dollars: deflated to FY27 baseline using the inflation series in inputs."
            >
              Real (FY27 $)
            </button>
          </div>
          {autoLinkOn && (
            <span
              className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full bg-purple text-white text-xs font-semibold uppercase tracking-wider shadow-sm border border-purple-300"
              title="Projection is using the philanthropic decomposition (Committed + haircut × Likely) instead of the raw fundraising target."
            >
              <span aria-hidden="true">●</span>
              Auto-linked
            </span>
          )}
          <button
            onClick={() => window.print()}
            className="no-print inline-flex items-center gap-1.5 px-3 py-1 rounded-full bg-white/10 border border-white/30 text-xs font-semibold uppercase tracking-wider hover:bg-white/20 transition-colors"
            title="Print this view (or save as PDF). Inputs panel and tab navigation are hidden in the printable output."
            aria-label="Print this view"
          >
            <span aria-hidden="true">⎙</span>
            Print
          </button>
          <div className="text-xs text-white/60 uppercase tracking-widest">Audience</div>
          <div className="px-3 py-1 rounded-full bg-purple/30 border border-purple/40 text-xs font-semibold uppercase tracking-wider">
            CEO · Board · Finance Cmte
          </div>
        </div>
      </div>
    </header>
  );
}
