import { useMemo, useRef, useState } from 'react';
import { Header } from './components/Header';
import type { ViewMode } from './components/Header';
import { InputsPanel } from './components/InputsPanel';
import { Brief } from './components/tabs/Brief';
import { ScenarioOverview } from './components/tabs/ScenarioOverview';
import { PhilanthropicProjection } from './components/tabs/PhilanthropicProjection';
import { EndowmentRunway } from './components/tabs/EndowmentRunway';
import { SensitivityTornado } from './components/tabs/SensitivityTornado';
import { MonteCarloStress } from './components/tabs/MonteCarloStress';
import { GoalSeek } from './components/tabs/GoalSeek';
import { DEFAULT_INPUTS, cumulativeInflationFactors } from './lib/model';
import type { FinancialInputs } from './lib/model';

type TabKey =
  | 'brief'
  | 'scenarios'
  | 'philanthropic'
  | 'runway'
  | 'sensitivity'
  | 'monteCarlo'
  | 'goalSeek';

export interface AutoLinkConfig {
  enabled: boolean;
  /** Fraction of the "Likely / Renewals" line to count as effective fundraising (0–1). */
  haircut: number;
}

interface TabDef {
  key: TabKey;
  label: string;
  sub: string;
  /** Tabs are grouped: 'brief' is the CEO landing; 'analyst' is the depth view.
   *  Visual separator in the nav reinforces the audience switch. */
  group: 'brief' | 'analyst';
}

const TABS: TabDef[] = [
  { key: 'brief', label: 'Brief', sub: 'Recommended action · key numbers', group: 'brief' },
  { key: 'scenarios', label: 'Scenarios', sub: 'Per-year financial detail', group: 'analyst' },
  { key: 'philanthropic', label: 'Philanthropic', sub: 'Committed · Likely · Gap', group: 'analyst' },
  { key: 'runway', label: 'Runway', sub: 'Liquidity + spend rate guardrails', group: 'analyst' },
  { key: 'sensitivity', label: 'Sensitivity', sub: 'Tornado of input drivers', group: 'analyst' },
  { key: 'monteCarlo', label: 'Stress Test', sub: 'Monte Carlo distribution', group: 'analyst' },
  { key: 'goalSeek', label: 'Goal-Seek', sub: 'Solve backwards from a target', group: 'analyst' },
];

export default function App() {
  const [inputs, setInputs] = useState<FinancialInputs>(DEFAULT_INPUTS);
  const [tab, setTab] = useState<TabKey>('brief');
  const [autoLink, setAutoLink] = useState<AutoLinkConfig>({ enabled: false, haircut: 0.7 });
  const [viewMode, setViewMode] = useState<ViewMode>('nominal');
  // Inputs panel: collapsed by default. CEO landing keeps the screen clean;
  // analyst clicks "Adjust assumptions" to expand the full controls.
  const [inputsOpen, setInputsOpen] = useState<boolean>(false);
  const [showAnalyst, setShowAnalyst] = useState<boolean>(false);
  const inputsRef = useRef<HTMLDivElement | null>(null);

  /**
   * Effective inputs: when philanthropic auto-link is enabled, the projection's
   * fundraising line is replaced with Committed + (haircut × Likely) per year.
   * The Gap is intentionally excluded — it is the "to-find" closing problem and
   * the whole point of the auto-link is to model the discipline of NOT counting it.
   * The original `inputs` is preserved so editing the decomposition still works.
   */
  const effectiveInputs = useMemo<FinancialInputs>(() => {
    if (!autoLink.enabled) return inputs;
    return {
      ...inputs,
      fundraising: inputs.philanthropic.map(
        (p) => p.committed + p.likely * autoLink.haircut
      ),
    };
  }, [inputs, autoLink]);

  /** Cumulative inflation factor per projection year, used to deflate dollar
   *  metrics when viewMode === 'real'. Display-only transformation; the
   *  underlying projection always runs in nominal $. */
  const cumInflation = useMemo(
    () => cumulativeInflationFactors(effectiveInputs.inflation),
    [effectiveInputs.inflation]
  );

  // Defensive flag for the auto-link bug: when on but the decomposition sums
  // to 0 across all years, the projection silently runs at $0 fundraising.
  // Surfaced as a banner.
  const autoLinkProducingZero =
    autoLink.enabled &&
    inputs.philanthropic.every((p) => p.committed + p.likely === 0);

  const today = new Date().toLocaleDateString('en-US', {
    year: 'numeric',
    month: 'long',
    day: 'numeric',
  });

  // Tabs visible in the nav: Brief is always visible. Analyst tabs only when
  // user has explicitly opened them via the "Show analyst tools" toggle.
  const visibleTabs = TABS.filter((t) => t.group === 'brief' || showAnalyst);

  const openInputs = () => {
    setInputsOpen(true);
    requestAnimationFrame(() => {
      inputsRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
    });
  };

  return (
    <div className="min-h-screen flex flex-col">
      <Header asOf={today} autoLinkOn={autoLink.enabled} viewMode={viewMode} setViewMode={setViewMode} />

      <a
        href="#main-content"
        className="sr-only focus:not-sr-only focus:absolute focus:top-2 focus:left-2 focus:z-50 focus:bg-purple focus:text-white focus:px-3 focus:py-2 focus:rounded no-print"
      >
        Skip to content
      </a>

      <nav className="bg-white border-b border-navy/10 no-print" aria-label="Tool sections">
        <div className="max-w-screen-2xl mx-auto px-6">
          <div
            className="flex items-end gap-1 overflow-x-auto -mb-px"
            role="tablist"
            aria-orientation="horizontal"
          >
            {visibleTabs.map((t, idx) => {
              const selected = tab === t.key;
              const prevGroup = visibleTabs[idx - 1]?.group;
              const showSeparator = prevGroup === 'brief' && t.group === 'analyst';
              return (
                <span key={t.key} className="flex items-end">
                  {showSeparator && (
                    <span
                      className="self-center mx-2 px-2 py-1 text-[10px] uppercase tracking-widest text-navy/40 font-semibold border-l border-navy/10"
                      aria-hidden="true"
                    >
                      Analyst tools
                    </span>
                  )}
                  <button
                    id={`tab-${t.key}`}
                    role="tab"
                    aria-selected={selected}
                    aria-controls={`tabpanel-${t.key}`}
                    tabIndex={selected ? 0 : -1}
                    onClick={() => setTab(t.key)}
                    onKeyDown={(e) => {
                      if (e.key === 'ArrowRight' || e.key === 'ArrowLeft') {
                        e.preventDefault();
                        const idx = visibleTabs.findIndex((x) => x.key === tab);
                        const next =
                          e.key === 'ArrowRight'
                            ? visibleTabs[(idx + 1) % visibleTabs.length]
                            : visibleTabs[(idx - 1 + visibleTabs.length) % visibleTabs.length];
                        setTab(next.key);
                        requestAnimationFrame(() => {
                          document.getElementById(`tab-${next.key}`)?.focus();
                        });
                      }
                    }}
                    className={`px-4 py-3 text-left border-b-2 transition-colors whitespace-nowrap ${
                      selected
                        ? 'border-purple text-navy'
                        : 'border-transparent text-navy/60 hover:text-navy hover:border-navy/30'
                    }`}
                  >
                    <div className="font-head uppercase tracking-wide-15 text-sm">{t.label}</div>
                    <div className="text-[11px] text-navy/70 font-sub">{t.sub}</div>
                  </button>
                </span>
              );
            })}
            {/* Show / hide analyst tools — single toggle that flips visibility
                of the 6 analyst tabs. CEO never sees them; analyst clicks once. */}
            <button
              onClick={() => {
                const next = !showAnalyst;
                setShowAnalyst(next);
                if (!next) setTab('brief');
              }}
              className="ml-auto self-center px-3 py-1.5 text-xs font-semibold uppercase tracking-wider text-purple hover:text-navy transition-colors"
              aria-pressed={showAnalyst}
            >
              {showAnalyst ? '▴ Hide analyst tools' : '▾ Show analyst tools'}
            </button>
          </div>
          {autoLinkProducingZero && (
            <div className="text-[11px] font-semibold uppercase tracking-wider text-rose-700 bg-rose-50 py-1.5 px-3 border-t border-rose-200" role="alert">
              ✕ Auto-link mode is producing $0 fundraising every year — Committed + Likely sums to 0 in your decomposition. Edit the per-year decomposition on the Philanthropic tab, or toggle off auto-link.
            </div>
          )}
          {autoLink.enabled && !autoLinkProducingZero && (
            <div className="text-[11px] font-semibold uppercase tracking-wider text-purple py-1.5 border-t border-navy/5">
              Projection auto-linked to philanthropic decomposition · Effective fundraising = Committed + {Math.round(autoLink.haircut * 100)}% × Likely
            </div>
          )}
        </div>
      </nav>

      <main id="main-content" className="flex-1 bg-tan/40">
        <div className="max-w-screen-2xl mx-auto px-6 py-6">
          {/* The Brief / detail content comes FIRST. The recommendation card
              must be the very first thing on the page (per Eric's audit). The
              "Adjust assumptions" trigger sits at the BOTTOM where power users
              who need it can find it without it stealing the eye on first scan. */}
          <div role="tabpanel" id={`tabpanel-${tab}`} aria-labelledby={`tab-${tab}`} tabIndex={0}>
            {tab === 'brief' && (
              <Brief
                inputs={effectiveInputs}
                viewMode={viewMode}
                cumInflation={cumInflation}
                onEditAssumptions={openInputs}
              />
            )}
            {tab === 'scenarios' && (
              <ScenarioOverview
                inputs={effectiveInputs}
                viewMode={viewMode}
                cumInflation={cumInflation}
              />
            )}
            {tab === 'philanthropic' && (
              <PhilanthropicProjection
                inputs={inputs}
                setInputs={setInputs}
                autoLink={autoLink}
                setAutoLink={setAutoLink}
              />
            )}
            {tab === 'runway' && (
              <EndowmentRunway
                inputs={effectiveInputs}
                viewMode={viewMode}
                cumInflation={cumInflation}
              />
            )}
            {tab === 'sensitivity' && <SensitivityTornado inputs={effectiveInputs} />}
            {tab === 'monteCarlo' && <MonteCarloStress inputs={effectiveInputs} />}
            {tab === 'goalSeek' && <GoalSeek inputs={effectiveInputs} />}
          </div>

          {/* Inputs panel: collapsed-by-default drawer. CEOs never need this;
              power users click the "Adjust assumptions" button. Located AFTER
              the content so it doesn't pull focus off the headline. Same 5
              sub-tabs and 50+ fields preserved. */}
          <div ref={inputsRef} className="no-print mt-6">
            {!inputsOpen ? (
              <button
                onClick={() => setInputsOpen(true)}
                className="inline-flex items-center gap-2 px-3 py-1.5 rounded-md bg-white border border-navy/15 text-sm font-semibold text-navy hover:bg-tan transition-colors"
              >
                <span aria-hidden="true">⚙</span>
                Adjust assumptions
                <span className="text-xs text-navy/60 font-normal font-sub">
                  (fundraising · awards · op-ex · returns · policy · portfolio)
                </span>
              </button>
            ) : (
              <div className="grid grid-cols-1 lg:grid-cols-[20rem_1fr] gap-6">
                <div>
                  <button
                    onClick={() => setInputsOpen(false)}
                    className="mb-2 text-xs font-semibold uppercase tracking-wider text-navy/70 hover:text-navy"
                  >
                    ▴ Collapse assumptions
                  </button>
                  <InputsPanel inputs={inputs} setInputs={setInputs} />
                </div>
                <div className="text-xs text-navy/70 font-sub italic">
                  Editing here updates every view live. Per-year fundraising, awards, op-ex, market returns
                  by scenario, stress library, mission/policy/portfolio settings — all preserved.
                </div>
              </div>
            )}
          </div>
        </div>
      </main>

      <footer className="bg-navy text-white/70 text-xs no-print">
        <div className="max-w-screen-2xl mx-auto px-6 py-4 flex items-center justify-between flex-wrap gap-2">
          <div>DC CAP Innovation Hub · Financial Scenarios · Draft for Finance Committee review</div>
          <div className="font-head uppercase tracking-wide-15 text-purple-100">Excel Beyond Belief</div>
        </div>
      </footer>
    </div>
  );
}
