import { useMemo } from 'react';
import {
  Bar,
  CartesianGrid,
  ComposedChart,
  LabelList,
  Line,
  ResponsiveContainer,
  Tooltip,
  XAxis,
  YAxis,
} from 'recharts';
import type { FinancialInputs, PhilanthropicYear } from '../../lib/model';
import { fiscalYears, reconcilePhilanthropic } from '../../lib/model';
import { dollars, fyLabel, millions, percent } from '../../lib/format';
import { PHILANTHROPIC_COLORS } from '../../lib/colors';
import { RecommendedAction } from '../RecommendedAction';
import type { AutoLinkConfig } from '../../App';

interface Props {
  inputs: FinancialInputs;
  setInputs: (next: FinancialInputs) => void;
  autoLink: AutoLinkConfig;
  setAutoLink: (next: AutoLinkConfig) => void;
}

const GAP_PATTERN_ID = 'dccap-gap-pattern';

export function PhilanthropicProjection({ inputs, setInputs, autoLink, setAutoLink }: Props) {
  const years = fiscalYears();
  const reconciliation = useMemo(() => reconcilePhilanthropic(inputs), [inputs]);

  const chartData = useMemo(
    () =>
      years.map((fy, i) => ({
        fy,
        fyLabel: fyLabel(fy),
        committed: inputs.philanthropic[i].committed,
        likely: inputs.philanthropic[i].likely,
        gap: inputs.philanthropic[i].gap,
        target: inputs.fundraising[i] ?? 0,
        total:
          inputs.philanthropic[i].committed +
          inputs.philanthropic[i].likely +
          inputs.philanthropic[i].gap,
      })),
    [inputs.philanthropic, inputs.fundraising, years]
  );

  const updatePhilanthropic = (
    idx: number,
    field: keyof PhilanthropicYear,
    valueDollars: number
  ) => {
    const next = inputs.philanthropic.map((p, i) =>
      i === idx ? { ...p, [field]: valueDollars } : p
    );
    setInputs({ ...inputs, philanthropic: next });
  };

  const setGapToTarget = (idx: number) => {
    const target = inputs.fundraising[idx] ?? 0;
    const p = inputs.philanthropic[idx];
    const gap = Math.max(0, target - p.committed - p.likely);
    const next = inputs.philanthropic.map((q, i) => (i === idx ? { ...q, gap } : q));
    setInputs({ ...inputs, philanthropic: next });
  };

  const yMax = Math.max(
    ...chartData.map((d) => d.total),
    ...inputs.fundraising,
    1_000_000
  );

  const haircutPct = Math.round(autoLink.haircut * 100);
  const effectiveFundraising = inputs.philanthropic.map(
    (p) => p.committed + p.likely * autoLink.haircut
  );

  // Aggregate philanthropy state across the window: how much of the cumulative
  // target is secured vs. remaining gap. Drives the recommended-action panel.
  const totalTarget = inputs.fundraising.reduce((acc, v) => acc + v, 0);
  const totalCommitted = inputs.philanthropic.reduce((acc, p) => acc + p.committed, 0);
  const totalLikely = inputs.philanthropic.reduce((acc, p) => acc + p.likely, 0);
  const totalGap = inputs.philanthropic.reduce((acc, p) => acc + p.gap, 0);
  const pctSecured = totalTarget > 0 ? (totalCommitted + totalLikely) / totalTarget : 0;
  const philRec =
    pctSecured >= 0.85
      ? {
          severity: 'on-track' as const,
          headline: `Pipeline is ${percent(pctSecured, 0)} secured across the 9-year window`,
          rationale: (
            <>
              Committed + Likely covers <strong>{percent(pctSecured, 0)}</strong> of the cumulative
              fundraising target ({millions(totalCommitted + totalLikely)} of{' '}
              {millions(totalTarget)}). Remaining gap: <strong>{millions(totalGap)}</strong>. Continue
              normal pipeline conversion cadence.
            </>
          ),
          actions: [
            'Confirm Likely close rates with the development team quarterly.',
            'Use the auto-link toggle to stress-test what the projection looks like under conservative haircut assumptions.',
          ],
        }
      : pctSecured >= 0.55
        ? {
            severity: 'watch' as const,
            headline: `Pipeline at ${percent(pctSecured, 0)} secured — gap remains ${millions(totalGap)}`,
            rationale: (
              <>
                Committed + Likely covers <strong>{percent(pctSecured, 0)}</strong> of the
                9-year target. Remaining gap is <strong>{millions(totalGap)}</strong>. Within
                normal range for early-cycle pipeline; intentionality required to close.
              </>
            ),
            actions: [
              'Prioritize Likely → Committed conversion in the next two quarters.',
              'Identify named prospects for the gap; assign portfolio responsibility.',
              'Toggle auto-link ON to see what FY35 endowment looks like if the gap does not close.',
            ],
          }
        : {
            severity: 'urgent' as const,
            headline: `Pipeline well below target — ${percent(pctSecured, 0)} secured, ${millions(totalGap)} gap`,
            rationale: (
              <>
                Committed + Likely is only <strong>{percent(pctSecured, 0)}</strong> of the 9-year
                target. The implied gap (<strong>{millions(totalGap)}</strong>) is large enough that
                projections relying on the raw fundraising line should be treated skeptically.
              </>
            ),
            actions: [
              'Toggle the auto-link ON to surface what every other tab looks like without the gap closing.',
              'Brief the Development Committee on the FY27–FY35 pipeline gap.',
              'Consider a campaign-feasibility study if the gap is not closeable through annual giving.',
            ],
          };

  return (
    <div className="space-y-6">
      <RecommendedAction
        context="Philanthropy · recommended action"
        severity={philRec.severity}
        headline={philRec.headline}
        rationale={philRec.rationale}
        actions={philRec.actions}
      />

      {/* Auto-link toggle: drives whether the org-wide projection uses the
          philanthropic decomposition (Committed + haircut × Likely) instead of the
          raw fundraising target. State lives in App.tsx; this is the only place
          to flip it from. */}
      <section
        className={`card border-2 ${
          autoLink.enabled ? 'border-purple bg-purple/5' : 'border-navy/10'
        }`}
      >
        <div className="card-body flex flex-wrap items-center justify-between gap-4">
          <div className="flex items-start gap-3">
            <button
              type="button"
              role="switch"
              aria-checked={autoLink.enabled}
              aria-label="Auto-link projection to philanthropic decomposition"
              onClick={() => setAutoLink({ ...autoLink, enabled: !autoLink.enabled })}
              className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${
                autoLink.enabled ? 'bg-purple' : 'bg-navy/20'
              }`}
            >
              <span
                className={`inline-block h-4 w-4 transform rounded-full bg-white shadow-sm transition-transform ${
                  autoLink.enabled ? 'translate-x-6' : 'translate-x-1'
                }`}
              />
            </button>
            <span className="font-head text-sm uppercase tracking-wide-15 text-navy">
              Auto-link projection to philanthropic decomposition
            </span>
          </div>
          <div className="flex items-center gap-2 text-sm">
            <label className="text-navy/70 font-semibold">Likely haircut:</label>
            <input
              type="number"
              step="5"
              min="0"
              max="100"
              className="input-num w-20"
              value={haircutPct}
              onChange={(e) =>
                setAutoLink({
                  ...autoLink,
                  haircut: Math.max(0, Math.min(100, Number(e.target.value))) / 100,
                })
              }
              disabled={!autoLink.enabled}
            />
            <span className="text-navy/60">%</span>
          </div>
        </div>
        <div className="card-body border-t border-navy/10 text-xs text-navy/70 font-sub">
          When ON, every other tab's projection uses{' '}
          <strong className="text-navy">Committed + {haircutPct}% × Likely</strong>{' '}
          per year as the effective fundraising line — the Gap is excluded. Use this
          to stress-test what happens if the "to-find" portion of the target does not
          close. The fundraising target in the inputs panel is preserved as the
          aspirational goal-state but no longer drives the projection.
        </div>
      </section>

      {/* SVG defs registered globally for the pattern fill */}
      <svg width={0} height={0} className="absolute">
        <defs>
          <pattern
            id={GAP_PATTERN_ID}
            patternUnits="userSpaceOnUse"
            width="10"
            height="10"
            patternTransform="rotate(45)"
          >
            <rect width="10" height="10" fill="#FFF4ED" />
            <line x1="0" y1="0" x2="0" y2="10" stroke={PHILANTHROPIC_COLORS.gap} strokeWidth={3} />
          </pattern>
        </defs>
      </svg>

      <section className="card">
        <div className="card-header flex items-center justify-between flex-wrap gap-3">
          <div>
            <div className="eyebrow">Philanthropic revenue projection</div>
            <h2 className="font-head text-base">FY27 – FY35 · Committed vs. Likely vs. Gap</h2>
          </div>
          <Legend />
        </div>
        <div className="card-body">
          <div className="h-[420px]">
            <ResponsiveContainer width="100%" height="100%">
              <ComposedChart
                data={chartData}
                margin={{ top: 36, right: 24, bottom: 8, left: 8 }}
                barCategoryGap="22%"
              >
                <CartesianGrid strokeDasharray="2 4" stroke="#101A4C15" vertical={false} />
                <XAxis
                  dataKey="fyLabel"
                  tick={{ fill: '#101A4C', fontSize: 13, fontWeight: 600 }}
                  stroke="#101A4C40"
                  tickLine={false}
                />
                <YAxis
                  domain={[0, Math.ceil((yMax * 1.18) / 1_000_000) * 1_000_000]}
                  tick={{ fill: '#101A4C', fontSize: 12 }}
                  tickFormatter={(v) => `$${(v / 1_000_000).toFixed(0)}M`}
                  stroke="#101A4C40"
                  width={64}
                />
                <Tooltip
                  cursor={{ fill: '#101A4C08' }}
                  contentStyle={{
                    background: 'white',
                    border: '1px solid #101A4C20',
                    borderRadius: 8,
                    fontFamily: 'Noto Serif, serif',
                  }}
                  formatter={(v: number, name: string) => [millions(v), name]}
                  labelFormatter={(label) => `Fiscal year ${label}`}
                />
                <Bar
                  dataKey="committed"
                  stackId="a"
                  fill={PHILANTHROPIC_COLORS.committed}
                  name="Committed"
                  radius={[0, 0, 0, 0]}
                />
                <Bar
                  dataKey="likely"
                  stackId="a"
                  fill={PHILANTHROPIC_COLORS.likely}
                  name="Likely / Renewals"
                />
                <Bar
                  dataKey="gap"
                  stackId="a"
                  fill={`url(#${GAP_PATTERN_ID})`}
                  stroke={PHILANTHROPIC_COLORS.gap}
                  strokeWidth={1.5}
                  name="Gap"
                  radius={[6, 6, 0, 0]}
                >
                  <LabelList
                    dataKey="total"
                    position="top"
                    formatter={(v: number) => millions(v, v >= 10_000_000 ? 0 : 1)}
                    fill="#101A4C"
                    fontSize={13}
                    fontWeight={700}
                    offset={10}
                  />
                </Bar>
                {/* Fundraising target reference line — overlays bars so variance reads at a glance. */}
                <Line
                  type="stepAfter"
                  dataKey="target"
                  name="Fundraising target"
                  stroke="#101A4C"
                  strokeWidth={2}
                  strokeDasharray="6 4"
                  dot={{ r: 4, fill: 'white', stroke: '#101A4C', strokeWidth: 2 }}
                  activeDot={{ r: 5 }}
                  isAnimationActive={false}
                />
              </ComposedChart>
            </ResponsiveContainer>
          </div>

          {/* Per-year secured/committed quick read */}
          <div className="grid grid-cols-3 md:grid-cols-9 gap-2 mt-4">
            {reconciliation.map((r) => {
              const securedBand =
                r.pctSecured >= 0.85
                  ? 'pill-green'
                  : r.pctSecured >= 0.55
                    ? 'pill-yellow'
                    : 'pill-red';
              return (
                <div key={r.fiscalYear} className="text-center">
                  <div className="text-xs uppercase tracking-wider text-navy/60 font-head">
                    {fyLabel(r.fiscalYear)}
                  </div>
                  <div className={`pill mt-1 ${securedBand}`}>
                    {percent(r.pctSecured, 0)} secured
                  </div>
                  <div className="text-[10px] text-navy/60 mt-0.5">
                    {percent(r.pctCommitted, 0)} committed
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      </section>

      {/* Editable per-year inputs */}
      <section className="card">
        <div className="card-header flex items-center justify-between">
          <div>
            <div className="eyebrow">Edit projection</div>
            <h2 className="font-head text-base">Per-year revenue decomposition</h2>
          </div>
          <p className="text-xs text-navy/60 max-w-md text-right hidden md:block font-sub">
            Committed + Likely + Gap should equal the fundraising target. Variance flagged when off.
          </p>
        </div>
        <div className="card-body overflow-x-auto">
          <table className="w-full text-sm num">
            <thead>
              <tr className="text-navy/60 uppercase text-xs tracking-wider">
                <th className="text-left py-2 pr-4 font-semibold">Year</th>
                <th className="text-right px-3 py-2 font-semibold">Target ($M)</th>
                <th className="text-right px-3 py-2 font-semibold">Committed ($M)</th>
                <th className="text-right px-3 py-2 font-semibold">Likely / Renewals ($M)</th>
                <th className="text-right px-3 py-2 font-semibold">Gap ($M)</th>
                <th className="text-right px-3 py-2 font-semibold">Total</th>
                <th className="text-right px-3 py-2 font-semibold">Variance</th>
                {autoLink.enabled && (
                  <th
                    className="text-right px-3 py-2 font-semibold text-purple"
                    title={`Committed + ${haircutPct}% × Likely`}
                  >
                    Effective ($M)
                  </th>
                )}
                <th className="text-right px-3 py-2 font-semibold no-print"></th>
              </tr>
            </thead>
            <tbody>
              {years.map((fy, i) => {
                const r = reconciliation[i];
                const target = inputs.fundraising[i];
                const p = inputs.philanthropic[i];
                const varianceBand =
                  Math.abs(r.variance) < 100_000
                    ? 'text-emerald-700'
                    : 'text-rose-700';
                return (
                  <tr key={fy} className="border-b border-navy/5">
                    <td className="text-left py-2 pr-4 font-semibold text-navy">{fyLabel(fy)}</td>
                    <td className="text-right px-3 py-2 text-navy/80">
                      {(target / 1_000_000).toFixed(1)}
                    </td>
                    <td className="text-right px-3 py-2">
                      <input
                        className="input-num"
                        type="number"
                        step="0.1"
                        value={(p.committed / 1_000_000).toFixed(1)}
                        onChange={(e) =>
                          updatePhilanthropic(i, 'committed', Number(e.target.value) * 1_000_000)
                        }
                      />
                    </td>
                    <td className="text-right px-3 py-2">
                      <input
                        className="input-num"
                        type="number"
                        step="0.1"
                        value={(p.likely / 1_000_000).toFixed(1)}
                        onChange={(e) =>
                          updatePhilanthropic(i, 'likely', Number(e.target.value) * 1_000_000)
                        }
                      />
                    </td>
                    <td className="text-right px-3 py-2">
                      <input
                        className="input-num"
                        type="number"
                        step="0.1"
                        value={(p.gap / 1_000_000).toFixed(1)}
                        onChange={(e) =>
                          updatePhilanthropic(i, 'gap', Number(e.target.value) * 1_000_000)
                        }
                      />
                    </td>
                    <td className="text-right px-3 py-2 font-semibold">
                      {dollars(r.total)}
                    </td>
                    <td className={`text-right px-3 py-2 font-semibold ${varianceBand}`}>
                      {r.variance === 0 ? '—' : dollars(r.variance)}
                    </td>
                    {autoLink.enabled && (
                      <td className="text-right px-3 py-2 font-semibold text-purple num">
                        {(effectiveFundraising[i] / 1_000_000).toFixed(1)}
                      </td>
                    )}
                    <td className="text-right px-3 py-2 no-print">
                      <button
                        onClick={() => setGapToTarget(i)}
                        className="text-xs text-purple hover:text-navy underline underline-offset-2"
                        title="Set Gap so Committed + Likely + Gap = Target"
                      >
                        balance
                      </button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
        <div className="card-body border-t border-navy/10 text-xs text-navy/70 font-sub">
          <p className="font-semibold mb-1 text-navy">How to read this view</p>
          <ul className="list-disc list-inside space-y-0.5">
            <li>
              <strong>Committed</strong> — signed gifts and pledges already counted as revenue. Lowest risk.
            </li>
            <li>
              <strong>Likely / Renewals</strong> — reasonable likelihood: renewing donors, late-stage proposals. Medium risk.
            </li>
            <li>
              <strong>Gap</strong> — the unfilled portion of the fundraising target. The "to-find" closing problem.
            </li>
            <li>
              The "% secured" badge is (Committed + Likely) / Target. Green ≥ 85% · Yellow ≥ 55% · Red below.
            </li>
          </ul>
        </div>
      </section>
    </div>
  );
}

function Legend() {
  return (
    <div className="flex flex-wrap items-center gap-4 text-xs font-semibold uppercase tracking-wider">
      <span className="flex items-center gap-2">
        <span className="inline-block w-3 h-3 rounded-sm" style={{ background: PHILANTHROPIC_COLORS.committed }} />
        Committed
      </span>
      <span className="flex items-center gap-2">
        <span className="inline-block w-3 h-3 rounded-sm" style={{ background: PHILANTHROPIC_COLORS.likely }} />
        Likely / Renewals
      </span>
      <span className="flex items-center gap-2">
        <span
          className="inline-block w-3 h-3 rounded-sm border"
          style={{
            borderColor: PHILANTHROPIC_COLORS.gap,
            background:
              `repeating-linear-gradient(45deg, #FFF4ED 0 4px, ${PHILANTHROPIC_COLORS.gap} 4px 6px)`,
          }}
        />
        Gap
      </span>
      <span className="flex items-center gap-2 text-navy/70">
        <span
          className="inline-block w-4 h-0 border-t-2 border-dashed"
          style={{ borderColor: '#101A4C' }}
        />
        Target
      </span>
    </div>
  );
}
