import { useMemo, useState } from 'react';
import {
  Area,
  CartesianGrid,
  ComposedChart,
  Line,
  ReferenceLine,
  ResponsiveContainer,
  Tooltip,
  XAxis,
  YAxis,
} from 'recharts';
import type { FinancialInputs } from '../../lib/model';
import { fiscalYears } from '../../lib/model';
import type { MCDistribution } from '../../lib/montecarlo';
import { BOOTSTRAP_RETURNS, runMonteCarlo } from '../../lib/montecarlo';
import { fyLabel, millions, percent } from '../../lib/format';
import { BRAND_BLUE, NAVY, PURPLE } from '../../lib/colors';
import { RecommendedAction } from '../RecommendedAction';

interface Props {
  inputs: FinancialInputs;
}

export function MonteCarloStress({ inputs }: Props) {
  const [meanReturn, setMeanReturn] = useState(6.5);
  const [stdReturn, setStdReturn] = useState(12);
  const [trials, setTrials] = useState(1000);
  const [floor, setFloor] = useState(40_000_000);
  const [df, setDf] = useState(6);
  const [distribution, setDistribution] = useState<MCDistribution>('studentT');

  // Re-run when inputs change. Trials = 1000 is fast enough.
  const result = useMemo(
    () =>
      runMonteCarlo(inputs, {
        meanReturn,
        stdReturn,
        trials,
        floor,
        df,
        distribution,
      }),
    [inputs, meanReturn, stdReturn, trials, floor, df, distribution]
  );

  // Bootstrap-series stats for the disclosure card.
  const bootstrapMean =
    BOOTSTRAP_RETURNS.reduce((a, b) => a + b, 0) / BOOTSTRAP_RETURNS.length;
  const bootstrapVar =
    BOOTSTRAP_RETURNS.reduce((acc, r) => acc + (r - bootstrapMean) ** 2, 0) /
    BOOTSTRAP_RETURNS.length;
  const bootstrapStd = Math.sqrt(bootstrapVar);

  const years = fiscalYears();

  const chartData = result.bands.map((b, i) => ({
    fyLabel: fyLabel(years[i]),
    p10: b.p10,
    p50: b.p50,
    p90: b.p90,
    // Recharts range-Area: a tuple [low, high] for the band fill. Replaces the
    // earlier two-Area-with-overlay hack that painted over gridlines and floor.
    band: [b.p10, b.p90] as [number, number],
  }));

  // Histogram bins for the FY35 ending distribution
  const dist = result.endingDistribution;
  const min = dist[0];
  const max = dist[dist.length - 1];
  const binCount = 18;
  const binWidth = (max - min) / binCount;
  const bins = Array.from({ length: binCount }, (_, i) => {
    const lo = min + i * binWidth;
    const hi = lo + binWidth;
    const count = dist.filter((v) => v >= lo && (i === binCount - 1 ? v <= hi : v < hi)).length;
    return {
      bin: `${(lo / 1_000_000).toFixed(0)}`,
      lo,
      hi,
      count,
    };
  });

  // Recommended action: anchor on P(insolvency) — the tail-risk read.
  // <1% = on-track, 1-5% = watch, ≥5% = urgent.
  const mcRec =
    result.probInsolvent >= 0.05
      ? {
          severity: 'urgent' as const,
          headline: `Tail risk above 5% — Monte Carlo shows ${percent(result.probInsolvent, 1)} of paths reach insolvency`,
          rationale: (
            <>
              Across {result.trials.toLocaleString()} simulated paths,{' '}
              <strong>{percent(result.probInsolvent, 1)}</strong> end with the endowment going negative
              at some point. P(stayed ≥ {millions(floor)} every year):{' '}
              <strong>{percent(result.probAlwaysAboveFloor, 0)}</strong>. Above the threshold a Finance
              Committee would accept without action.
            </>
          ),
          actions: [
            'Reduce program-side exposure (lower fundraising target = lower required draw, OR adjust award policy).',
            'Increase fundraising assumption (test what flat fundraising drops insolvency probability below 1%).',
            'Increase the floor / quasi-redesignation policy to absorb tail outcomes.',
          ],
        }
      : result.probInsolvent >= 0.01
        ? {
            severity: 'watch' as const,
            headline: `Tail risk in the 1–5% band — ${percent(result.probInsolvent, 1)} insolvency probability`,
            rationale: (
              <>
                Across {result.trials.toLocaleString()} simulated paths,{' '}
                <strong>{percent(result.probInsolvent, 1)}</strong> reach insolvency. P(stayed ≥{' '}
                {millions(floor)} every year): <strong>{percent(result.probAlwaysAboveFloor, 0)}</strong>.
                Watch territory; not yet an urgent action.
              </>
            ),
            actions: [
              'Confirm the current fundraising trajectory and award assumptions are realistic.',
              'Consider tightening the spending policy (lower rate, longer smoothing) to reduce tail risk.',
            ],
          }
        : {
            severity: 'on-track' as const,
            headline: `Tail risk below 1% — Monte Carlo shows the org is robust`,
            rationale: (
              <>
                Across {result.trials.toLocaleString()} simulated paths, P(insolvency) is{' '}
                <strong>{percent(result.probInsolvent, 1)}</strong>. P(stayed ≥ {millions(floor)} every
                year): <strong>{percent(result.probAlwaysAboveFloor, 0)}</strong>. Plan is robust to
                stochastic shocks.
              </>
            ),
            actions: [
              'Annual review at the Finance Committee — no structural change required.',
              'Use the deterministic Pessimistic case as the planning anchor, not the MC tails.',
            ],
          };

  return (
    <div className="space-y-6">
      <RecommendedAction
        context="Monte Carlo stress test · recommended action"
        severity={mcRec.severity}
        headline={mcRec.headline}
        rationale={mcRec.rationale}
        actions={mcRec.actions}
      />

      <section className="card">
        <div className="card-header flex items-center justify-between flex-wrap gap-3">
          <div>
            <div className="eyebrow">Monte Carlo stress test</div>
            <h2 className="font-head text-base">
              {trials.toLocaleString()} simulated paths ·{' '}
              {distribution === 'bootstrap'
                ? `bootstrap from NACUBO FY94–FY24 (μ̂≈${bootstrapMean.toFixed(1)}%, σ̂≈${bootstrapStd.toFixed(1)}%)`
                : `Student-t(df=${df}, μ=${meanReturn}%, σ=${stdReturn}%)`}
            </h2>
          </div>
          <div className="flex flex-wrap items-center gap-3 text-sm">
            <span className="flex items-center gap-1.5 whitespace-nowrap">
              <span className="text-navy/70 font-semibold text-xs uppercase tracking-wider">Distribution</span>
              <select
                className="input-num min-w-[10rem]"
                value={distribution}
                onChange={(e) => setDistribution(e.target.value as MCDistribution)}
              >
                <option value="studentT">Student-t (parametric)</option>
                <option value="bootstrap">Bootstrap (NACUBO 31-yr)</option>
              </select>
            </span>
            {distribution === 'studentT' && (
              <>
                <Knob label="Mean (%)" value={meanReturn} step={0.1} onChange={setMeanReturn} />
                <Knob label="Std (%)" value={stdReturn} step={0.5} onChange={setStdReturn} />
                <Knob
                  label="df (tail)"
                  value={df}
                  step={1}
                  onChange={(v) => setDf(Math.max(3, Math.round(v)))}
                />
              </>
            )}
            <Knob label="Trials" value={trials} step={500} onChange={setTrials} />
            <Knob
              label="Floor ($M)"
              value={floor / 1_000_000}
              step={1}
              onChange={(v) => setFloor(v * 1_000_000)}
            />
          </div>
        </div>
        <div className="card-body">
          <div className="grid grid-cols-2 md:grid-cols-4 gap-3 mb-4">
            <Stat
              label="Median FY35 endowment"
              value={millions(result.bands[result.bands.length - 1].p50)}
              accent="navy"
            />
            <Stat
              label={`P(FY35 ≥ ${millions(floor)})`}
              value={percent(result.probAboveFloor, 0)}
              accent={result.probAboveFloor >= 0.85 ? 'green' : result.probAboveFloor >= 0.6 ? 'yellow' : 'red'}
            />
            <Stat
              label={`P(stayed ≥ ${millions(floor)} every yr)`}
              value={percent(result.probAlwaysAboveFloor, 0)}
              accent={result.probAlwaysAboveFloor >= 0.85 ? 'green' : result.probAlwaysAboveFloor >= 0.6 ? 'yellow' : 'red'}
            />
            <Stat
              label="P(insolvency at any point)"
              value={percent(result.probInsolvent, 1)}
              accent={result.probInsolvent === 0 ? 'green' : result.probInsolvent < 0.05 ? 'yellow' : 'red'}
            />
          </div>

          <div className="h-[340px]">
            <ResponsiveContainer width="100%" height="100%">
              <ComposedChart data={chartData} margin={{ top: 10, right: 24, bottom: 8, left: 0 }}>
                <CartesianGrid strokeDasharray="2 4" stroke="#101A4C15" />
                <XAxis
                  dataKey="fyLabel"
                  tick={{ fill: '#101A4C', fontSize: 12 }}
                  stroke="#101A4C40"
                />
                <YAxis
                  tick={{ fill: '#101A4C', fontSize: 12 }}
                  tickFormatter={(v) => `$${(v / 1_000_000).toFixed(0)}M`}
                  stroke="#101A4C40"
                  width={64}
                />
                <Tooltip
                  contentStyle={{
                    background: 'white',
                    border: '1px solid #101A4C20',
                    borderRadius: 8,
                    fontFamily: 'Noto Serif, serif',
                  }}
                  formatter={(v: number) => millions(v)}
                />
                {/* Cone of outcomes: range-Area between p10 and p90 — single
                    Area component, no overlay hack. Won't paint over gridlines
                    or the floor reference line. */}
                <Area
                  type="monotone"
                  dataKey="band"
                  fill={BRAND_BLUE}
                  fillOpacity={0.32}
                  stroke="none"
                  isAnimationActive={false}
                  legendType="none"
                />
                <Line
                  type="monotone"
                  dataKey="p50"
                  stroke={NAVY}
                  strokeWidth={2.5}
                  dot={false}
                  isAnimationActive={false}
                  name="Median (p50)"
                />
                <Line
                  type="monotone"
                  dataKey="p10"
                  stroke={PURPLE}
                  strokeWidth={1.5}
                  strokeDasharray="4 4"
                  dot={false}
                  isAnimationActive={false}
                  name="p10 (downside)"
                />
                <Line
                  type="monotone"
                  dataKey="p90"
                  stroke={BRAND_BLUE}
                  strokeWidth={1.5}
                  strokeDasharray="4 4"
                  dot={false}
                  isAnimationActive={false}
                  name="p90 (upside)"
                />
                <ReferenceLine
                  y={floor}
                  stroke="#b91c1c"
                  strokeDasharray="2 4"
                  label={{
                    value: 'Floor',
                    position: 'right',
                    fill: '#b91c1c',
                    fontSize: 11,
                  }}
                />
              </ComposedChart>
            </ResponsiveContainer>
          </div>

          <div className="flex items-center gap-4 text-xs mt-2 font-sub">
            <span className="flex items-center gap-2">
              <span className="inline-block w-3 h-3" style={{ background: BRAND_BLUE, opacity: 0.45 }} />
              10th – 90th percentile cone
            </span>
            <span className="flex items-center gap-2">
              <span className="inline-block w-3 h-0.5" style={{ background: NAVY }} />
              Median (p50)
            </span>
            <span className="flex items-center gap-2">
              <span
                className="inline-block w-4 h-0 border-t-2 border-dashed"
                style={{ borderColor: PURPLE }}
              />
              p10 (downside)
            </span>
            <span className="flex items-center gap-2">
              <span
                className="inline-block w-4 h-0 border-t-2 border-dashed"
                style={{ borderColor: BRAND_BLUE }}
              />
              p90 (upside)
            </span>
          </div>
        </div>
      </section>

      <section className="card">
        <div className="card-header">
          <div className="eyebrow">Method</div>
          <h2 className="font-head text-base">Distribution &amp; assumptions</h2>
        </div>
        <div className="card-body text-xs text-navy/70 font-sub space-y-1">
          <p>
            {distribution === 'studentT' ? (
              <>
                Returns sampled IID across years from a Student-t distribution with{' '}
                <strong className="text-navy">df = {df}</strong>, normalized so the
                std-dev equals the configured σ = {stdReturn}%. Lower df → fatter tails;
                df ≥ 30 ≈ Gaussian. Default df=6 is calibrated to S&amp;P 500 fits — it
                captures 2008/2020-style downside at realistic frequency.
              </>
            ) : (
              <>
                Returns sampled IID with replacement from the{' '}
                <strong className="text-navy">NACUBO-Commonfund endowment composite, FY94–FY24</strong>{' '}
                (31 annual observations, mean ≈ {bootstrapMean.toFixed(1)}%, std-dev ≈{' '}
                {bootstrapStd.toFixed(1)}%). The series includes 2001/2002 dotcom bust
                (−3.6, −6), 2008/2009 GFC (−3, −19), 2021 boom (+30.6), and 2022 dual
                drawdown (−8). Yale-model practice — preserves real fat tails and real
                regime mix without needing parametric calibration. The mean/std/df knobs
                above don't apply.
              </>
            )}
          </p>
          <p>
            <strong className="text-navy">Pathwise vs. end-state:</strong>{' '}
            P(FY35 ≥ floor) is an end-state metric — a path can dip below the floor
            mid-projection and still recover by FY35. P(stayed ≥ floor every yr) is
            stricter and rules out transient dips. Use the pathwise stat for
            board-policy questions about minimum reserves.
          </p>
          <p>
            <strong className="text-navy">Independence assumption:</strong> per-year
            returns are independent — no autocorrelation, no volatility clustering,
            no regime-switching. Real markets cluster volatility, so successive bad
            years are slightly under-represented vs. reality. Treat this as
            optimistic at the tails even with t-draws.
          </p>
        </div>
      </section>

      <section className="card">
        <div className="card-header">
          <div className="eyebrow">FY35 ending distribution</div>
          <h2 className="font-head text-base">Histogram across {trials.toLocaleString()} trials</h2>
        </div>
        <div className="card-body">
          <div className="h-[220px]">
            <ResponsiveContainer width="100%" height="100%">
              <ComposedChart data={bins} margin={{ top: 10, right: 24, bottom: 8, left: 0 }}>
                <CartesianGrid strokeDasharray="2 4" stroke="#101A4C15" vertical={false} />
                <XAxis
                  dataKey="bin"
                  tick={{ fill: '#101A4C', fontSize: 11 }}
                  tickFormatter={(v) => `$${v}M`}
                  stroke="#101A4C40"
                />
                <YAxis tick={{ fill: '#101A4C', fontSize: 11 }} stroke="#101A4C40" width={32} />
                <Tooltip
                  contentStyle={{
                    background: 'white',
                    border: '1px solid #101A4C20',
                    borderRadius: 8,
                    fontFamily: 'Noto Serif, serif',
                  }}
                  formatter={(v: number) => `${v} trials`}
                  labelFormatter={(label) => `≈ $${label}M`}
                />
                <Area
                  type="step"
                  dataKey="count"
                  fill={NAVY}
                  fillOpacity={0.7}
                  stroke={NAVY}
                  strokeWidth={1}
                  isAnimationActive={false}
                />
                <ReferenceLine
                  x={`${(floor / 1_000_000).toFixed(0)}`}
                  stroke="#b91c1c"
                  strokeDasharray="2 4"
                  label={{ value: 'Floor', position: 'top', fill: '#b91c1c', fontSize: 10 }}
                />
              </ComposedChart>
            </ResponsiveContainer>
          </div>
        </div>
      </section>
    </div>
  );
}

function Knob({
  label,
  value,
  step,
  onChange,
}: {
  label: string;
  value: number;
  step: number;
  onChange: (v: number) => void;
}) {
  return (
    <span className="flex items-center gap-1.5 whitespace-nowrap">
      <span className="text-navy/70 font-semibold text-xs uppercase tracking-wider">{label}</span>
      <input
        type="number"
        step={step}
        className="input-num w-20"
        value={value}
        onChange={(e) => onChange(Number(e.target.value))}
      />
    </span>
  );
}

function Stat({
  label,
  value,
  accent,
}: {
  label: string;
  value: string;
  accent: 'navy' | 'green' | 'yellow' | 'red';
}) {
  const ring: Record<string, string> = {
    navy: 'border-navy/20 bg-white',
    green: 'border-emerald-300 bg-emerald-50',
    yellow: 'border-amber-300 bg-amber-50',
    red: 'border-rose-300 bg-rose-50',
  };
  const text: Record<string, string> = {
    navy: 'text-navy',
    green: 'text-emerald-800',
    yellow: 'text-amber-800',
    red: 'text-rose-800',
  };
  return (
    <div className={`rounded-lg border ${ring[accent]} px-4 py-3`}>
      <div className="text-xs uppercase tracking-wider text-navy/60 font-semibold">{label}</div>
      <div className={`text-xl font-head num mt-1 ${text[accent]}`}>{value}</div>
    </div>
  );
}
